#![no_std]
#![no_main]
//! 内核启动入口和初始化顺序。
//!
//! 这里保持启动链路尽量薄：完成架构最小初始化后，按 memory/process/syscall/fs/trap
//! 的依赖顺序建立运行态，再探测块设备并挂载测试文件系统进入 `/init`。

#[macro_use]
mod console;
mod arch;
mod drivers;
mod fs;
mod global_logger;
mod lang_item;
mod loader;
mod mm;
mod net;
mod process;
mod signal;
mod syscall;
mod uapi;

extern crate alloc;

use crate::arch::sbi::shutdown;
use arch::trap;
use core::{ffi::c_void, ptr};

fn clear_bss() {
    unsafe extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        ptr::write_bytes(
            sbss as *const () as usize as *mut c_void,
            0,
            ebss as *const () as usize - sbss as *const () as usize,
        );
    }
}

#[unsafe(no_mangle)]
#[cfg(target_arch = "riscv64")]
#[unsafe(link_section = ".text.main")]
pub fn fake_main(hart_id: usize, dtb_address: usize) {
    use crate::arch::config::KERNEL_BASE_OFFSET;
    unsafe {
        core::arch::asm!("add sp, sp, {}", in(reg) KERNEL_BASE_OFFSET);
        core::arch::asm!(
            "lla t1, __global_pointer$",
            "add gp, t1, {offset}",
            offset = in(reg) KERNEL_BASE_OFFSET,
            lateout("t1") _,
        );
        core::arch::asm!("la t0, rust_main");
        core::arch::asm!("add t0, t0, {}", in(reg) KERNEL_BASE_OFFSET);
        core::arch::asm!("mv a0, {}", in(reg) hart_id);
        core::arch::asm!("mv a1, {}", in(reg) dtb_address);
        core::arch::asm!("jalr zero, 0(t0)");
    }
}

#[unsafe(no_mangle)]
pub fn rust_main(_hart_id: usize, _dtb_address: usize) -> ! {
    clear_bss();
    // RISC-V 先从启动汇编修正后的 gp 取运行时值；LoongArch 当前不依赖该寄存器。
    unsafe {
        let gp_runtime: usize;
        #[cfg(target_arch = "riscv64")]
        core::arch::asm!("mv {}, gp", out(reg) gp_runtime);
        #[cfg(target_arch = "loongarch64")]
        {
            gp_runtime = 0;
        }
        crate::arch::KERNEL_GP_RUNTIME = gp_runtime;
    }
    #[cfg(target_arch = "loongarch64")]
    crate::arch::timer::init_clock_freq();
    mm::init();

    // 这些 runtime_state 是内核全局表，不依赖用户文件系统内容，必须在 trap/scheduler
    // 和用户态切换前完成初始化。
    process::init_runtime_state();
    syscall::init_runtime_state();
    fs::init_runtime_state();

    trap::init();
    mm::activate_kernel_space();

    drivers::init_runtime_state();
    global_logger::init();
    if test_block_device() {
        fs::init_filesystems();
        user_init();
    } else {
        println!("No block device found, exiting...");
        shutdown(false);
    }
}

/// 启动用户态 init 程序，若缺失则关机。
fn user_init() -> ! {
    if process::try_exec_from_path("/init") {
        unreachable!("try_exec_from_path('/init') should not return on success");
    }
    println!("[boot] no user init entry found in fs");
    shutdown(false);
}

/// 测试块设备，返回是否成功
fn test_block_device() -> bool {
    use alloc::vec;
    use drivers::BLOCK_DEVICE;
    if !drivers::block_device_available() {
        return false;
    }
    // 可用性探测
    let mut buf = vec![0u8; 512];
    if let Some(device) = BLOCK_DEVICE.lock().as_mut() {
        device.read_block(0, &mut buf);
        true
    } else {
        false
    }
}

//! Architecture facade selected at compile time.
//!
//! Higher layers import `crate::arch::*` through this module, so architecture
//! specific register, trap, timer and device details stay behind `target_arch`
//! cfg gates.

#[cfg(target_arch = "riscv64")]
mod riscv;
#[cfg(target_arch = "riscv64")]
pub use riscv::*;

#[cfg(target_arch = "loongarch64")]
mod loongarch;
#[cfg(target_arch = "loongarch64")]
pub use loongarch::*;

//! RISC v 接口抽象 将对 cx 的操作进行包装
//!
use core::arch::global_asm;

pub mod config;
pub mod drivers;
pub mod mm;
pub mod sbi;
pub mod timer;
pub mod trap;

global_asm!(include_str!("entry.S"));

#[unsafe(no_mangle)]
pub static mut KERNEL_GP_RUNTIME: usize = 0;

pub const MACHINE_NAME: &[u8] = b"riscv64";
pub const PLATFORM_NAME: &[u8] = b"riscv64\0";
pub const USER_INTERP_BASE: usize = 0x4000_0000;
pub const SIGNAL_TRAMPOLINE_CODE: &[u8] = &[
    0x93, 0x08, 0xb0, 0x08, // li a7, 139
    0x73, 0x00, 0x00, 0x00, // ecall
    0x73, 0x00, 0x10, 0x00, // ebreak (should not reach)
];

#[inline]
pub fn flush_tlb_all() {
    unsafe {
        core::arch::asm!("sfence.vma");
    }
}

#[inline]
pub fn flush_tlb_vaddr(va: usize) {
    unsafe {
        core::arch::asm!("sfence.vma {}", in(reg) va);
    }
}

#[inline]
pub fn get_user_stack_pointer(cx: &trap::TrapContext) -> usize {
    cx.user_stack_pointer()
}

#[inline]
pub fn set_user_stack_pointer(cx: &mut trap::TrapContext, sp: usize) {
    cx.set_user_stack_pointer(sp);
}

#[inline]
pub fn get_thread_pointer(cx: &trap::TrapContext) -> usize {
    cx.thread_pointer()
}

#[inline]
pub fn set_thread_pointer(cx: &mut trap::TrapContext, tp: usize) {
    cx.set_thread_pointer(tp);
}

#[inline]
pub fn get_syscall_return_value(cx: &trap::TrapContext) -> isize {
    cx.get_syscall_return_value()
}

#[inline]
pub fn set_syscall_return_value(cx: &mut trap::TrapContext, retval: isize) {
    cx.set_syscall_return_value(retval);
}

#[inline]
pub fn is_syscall_instruction(inst: &[u8]) -> bool {
    inst == [0x73, 0x00, 0x00, 0x00] // ecall 机器码为 0x0000_0073
}

#[inline]
pub fn restore_blocked_syscall_args(cx: &mut trap::TrapContext, syscall_args: &[usize; 6]) {
    cx.restore_syscall_args(syscall_args);
}

#[inline]
pub fn get_program_counter(cx: &trap::TrapContext) -> usize {
    cx.program_counter()
}

#[inline]
pub fn set_program_counter(cx: &mut trap::TrapContext, pc: usize) {
    cx.set_program_counter(pc);
}

#[inline]
pub fn advance_program_counter(cx: &mut trap::TrapContext, bytes: usize) {
    cx.advance_program_counter(bytes);
}

#[inline]
pub fn set_return_address(cx: &mut trap::TrapContext, ra: usize) {
    cx.set_return_address(ra);
}

#[inline]
pub fn initial_user_status() -> usize {
    let mut sstatus_val: usize;
    unsafe {
        core::arch::asm!("csrr {}, sstatus", out(reg) sstatus_val);
    }
    sstatus_val &= !0x100usize; // SPP = 0 -> U模式
    sstatus_val |= 0x20usize; // SPIE = 1 中断使能位打开
    sstatus_val &= !0x6000usize; // FS = Off，首次浮点指令走 lazy FPU
    sstatus_val
}

#[inline]
pub fn signal_trampoline_code() -> &'static [u8] {
    SIGNAL_TRAMPOLINE_CODE
}

#[inline]
pub fn set_signal_handler_args(
    cx: &mut trap::TrapContext,
    signo: i32,
    siginfo_ptr: usize,
    ucontext_ptr: usize,
) {
    cx.set_signal_handler_args(signo, siginfo_ptr, ucontext_ptr);
}

#[inline]
pub fn init_user_entry_registers(cx: &mut trap::TrapContext, gp: usize, tp: usize) {
    cx.init_user_entry_registers(gp, tp);
}
// 进程切换后 返回某个用户进程
#[inline]
pub fn prepare_user_trap_return(cx: &mut trap::TrapContext, token: usize) {
    cx.prepare_user_return_status();
    mm::activate_page_table(token);
    // SAFETY: Enabling supervisor timer interrupt is an idempotent CSR update
    // needed before returning to user mode.
    unsafe {
        core::arch::asm!(
            "csrs sie, {stie}",
            stie = in(reg) (1usize << 5),
        );
    }
}

#[inline]
pub fn set_user_fpu_state(cx: &mut trap::TrapContext, used_fpu: bool, _arch_bits: usize) {
    cx.set_user_fpu_enabled(used_fpu);
}

pub fn enter_first_user_mode(
    trap_cx_ptr: *const trap::TrapContext,
    token: usize,
    entry_point: usize,
) -> ! {
    unsafe {
        core::arch::asm!(
            "csrr t2, satp",
            "beq t2, {satp}, 1f",
            "csrw satp, {satp}",
            "sfence.vma",
            "1:",
            "csrs sie, {stie}",
            "csrw sepc, {sepc_val}",
            "csrw sscratch, {scratch_val}",
            "csrr t0, sscratch",
            "csrr t1, sstatus",
            "li t3, 0x100",
            "not t3, t3",
            "and t1, t1, t3",
            "ori t1, t1, 0x20",
            "li t3, 0x6000",
            "not t3, t3",
            "and t1, t1, t3",
            "csrw sstatus, t1",
            "ld x1, 1*8(t0)",
            "ld x3, 3*8(t0)",
            "ld x4, 4*8(t0)",
            "ld x6, 6*8(t0)",
            "ld x7, 7*8(t0)",
            "ld x8, 8*8(t0)",
            "ld x9, 9*8(t0)",
            "ld x10, 10*8(t0)",
            "ld x11, 11*8(t0)",
            "ld x12, 12*8(t0)",
            "ld x13, 13*8(t0)",
            "ld x14, 14*8(t0)",
            "ld x15, 15*8(t0)",
            "ld x16, 16*8(t0)",
            "ld x17, 17*8(t0)",
            "ld x18, 18*8(t0)",
            "ld x19, 19*8(t0)",
            "ld x20, 20*8(t0)",
            "ld x21, 21*8(t0)",
            "ld x22, 22*8(t0)",
            "ld x23, 23*8(t0)",
            "ld x24, 24*8(t0)",
            "ld x25, 25*8(t0)",
            "ld x26, 26*8(t0)",
            "ld x27, 27*8(t0)",
            "ld x28, 28*8(t0)",
            "ld x29, 29*8(t0)",
            "ld x30, 30*8(t0)",
            "ld x31, 31*8(t0)",
            "ld sp, 2*8(t0)",
            "ld t0, 5*8(t0)",
            "fence.i",
            "sret",
            satp = in(reg) token,
            stie = in(reg) (1usize << 5),
            sepc_val = in(reg) entry_point,
            scratch_val = in(reg) (trap_cx_ptr as usize),
            options(noreturn)
        );
    }
}

//! 接口层，对 cx 的操作进行包装
use core::arch::global_asm;

pub mod config;
pub mod drivers;
pub mod mm;
pub mod sbi;
pub mod timer;
pub mod trap;

global_asm!(include_str!("entry.S"));

#[unsafe(no_mangle)]
pub static mut KERNEL_GP_RUNTIME: usize = 0;

pub const MACHINE_NAME: &[u8] = b"loongarch64";
pub const PLATFORM_NAME: &[u8] = b"loongarch64\0";
pub const USER_INTERP_BASE: usize = 0x5000_0000;
pub const SIGNAL_TRAMPOLINE_CODE: &[u8] = &[
    0x0b, 0x2c, 0x82, 0x03, // li.w $a7, 139
    0x00, 0x00, 0x2b, 0x00, // syscall 0
    0x00, 0x00, 0x2a, 0x00, // break 0 (should not reach)
];

#[inline]
pub fn flush_tlb_all() {
    unsafe {
        core::arch::asm!("dbar 0; invtlb 0x0, $r0, $r0");
    }
}

#[inline]
pub fn flush_tlb_vaddr(_va: usize) {
    flush_tlb_all();
}

#[inline]
pub fn get_user_stack_pointer(cx: &trap::TrapContext) -> usize {
    cx.user_stack_pointer()
}

#[inline]
pub fn set_user_stack_pointer(cx: &mut trap::TrapContext, sp: usize) {
    cx.set_user_stack_pointer(sp);
}

#[inline]
pub fn get_thread_pointer(cx: &trap::TrapContext) -> usize {
    cx.thread_pointer()
}

#[inline]
pub fn set_thread_pointer(cx: &mut trap::TrapContext, tp: usize) {
    cx.set_thread_pointer(tp);
}

#[inline]
pub fn get_syscall_return_value(cx: &trap::TrapContext) -> isize {
    cx.syscall_return_value()
}

#[inline]
pub fn set_syscall_return_value(cx: &mut trap::TrapContext, retval: isize) {
    cx.set_syscall_return_value(retval);
}

#[inline]
pub fn is_syscall_instruction(inst: &[u8]) -> bool {
    inst == [0x00, 0x00, 0x2b, 0x00]
}

#[inline]
pub fn restore_blocked_syscall_args(cx: &mut trap::TrapContext, syscall_args: &[usize; 6]) {
    cx.restore_syscall_args(syscall_args);
}

#[inline]
pub fn get_program_counter(cx: &trap::TrapContext) -> usize {
    cx.program_counter()
}

#[inline]
pub fn set_program_counter(cx: &mut trap::TrapContext, pc: usize) {
    cx.set_program_counter(pc);
}

#[inline]
pub fn advance_program_counter(cx: &mut trap::TrapContext, bytes: usize) {
    cx.advance_program_counter(bytes);
}

#[inline]
pub fn set_return_address(cx: &mut trap::TrapContext, ra: usize) {
    cx.set_return_address(ra);
}

#[inline]
pub fn initial_user_status() -> usize {
    0b11 | (1 << 2)
}

#[inline]
pub fn signal_trampoline_code() -> &'static [u8] {
    SIGNAL_TRAMPOLINE_CODE
}

#[inline]
pub fn set_signal_handler_args(
    cx: &mut trap::TrapContext,
    signo: i32,
    siginfo_ptr: usize,
    ucontext_ptr: usize,
) {
    cx.set_signal_handler_args(signo, siginfo_ptr, ucontext_ptr);
}

#[inline]
pub fn init_user_entry_registers(cx: &mut trap::TrapContext, gp: usize, tp: usize) {
    cx.init_user_entry_registers(gp, tp);
}

#[inline]
pub fn prepare_user_trap_return(cx: &mut trap::TrapContext, token: usize) {
    cx.prepare_user_return_status();
    let root_pa = token << crate::arch::config::PAGE_SIZE_BITS;
    unsafe {
        core::arch::asm!(
            "csrwr {root}, 0x19",
            "csrwr {root}, 0x1a",
            "dbar 0",
            "invtlb 0x0, $r0, $r0",
            "ibar 0",
            root = in(reg) root_pa,
        );
    }
}

#[inline]
pub fn set_user_fpu_state(_cx: &mut trap::TrapContext, used_fpu: bool, arch_bits: usize) {
    const EUEN_FPU_LSX_LASX_MASK: usize = 0x7;
    let mut euen: usize;
    unsafe {
        core::arch::asm!("csrrd {value}, 0x2", value = out(reg) euen);
    }
    euen &= !EUEN_FPU_LSX_LASX_MASK;
    if used_fpu {
        let mut bits = arch_bits & EUEN_FPU_LSX_LASX_MASK;
        if (bits & (1usize << 2)) != 0 {
            bits |= 0x7;
        } else if (bits & (1usize << 1)) != 0 {
            bits |= 0x3;
        } else {
            bits |= 0x1;
        }
        euen |= bits;
    }
    unsafe {
        core::arch::asm!("csrwr {value}, 0x2", value = in(reg) euen);
    }
}

pub fn enter_first_user_mode(
    trap_cx_ptr: *const trap::TrapContext,
    token: usize,
    _entry_point: usize,
) -> ! {
    prepare_user_trap_return(
        unsafe { &mut *(trap_cx_ptr as *mut trap::TrapContext) },
        token,
    );
    set_user_fpu_state(
        unsafe { &mut *(trap_cx_ptr as *mut trap::TrapContext) },
        false,
        0,
    );
    unsafe extern "C" {
        fn __restore(cx: *mut trap::TrapContext) -> !;
    }
    unsafe {
        __restore(trap_cx_ptr as *mut trap::TrapContext);
    }
}

// ! Trap处理模块（RISC-V）
// !
// ! 常见寄存器：
// ! - 通用寄存器 x0..x31：
// !   - x0: 恒为 0
// !   - x1(ra): 返回地址
// !   - x2(sp): 栈指针
// !   - x3(gp): 全局指针
// !   - x4(tp): 线程指针/TLS 指针
// !   - x5..x7(t0..t2): 临时寄存器
// !   - x8(s0/fp), x9(s1), x18..x27(s2..s11): 被调用者保存
// !   - x10..x17(a0..a7): 参数/返回值（syscall 号在 a7）
// !   - x28..x31(t3..t6): 临时寄存器
// !
// ! - CSR（控制状态寄存器）：
// !   - stvec: trap 入口地址寄存器。init() 里写成 __alltraps。
// !   - scause: trap 原因（异常还是中断、具体类型）。
// !   - stval: trap 附加信息。页错误时通常是故障虚拟地址。
// !   - sepc: 触发 trap 的指令地址。syscall 后通常要 +4。
// !   - sstatus: S 模式状态位集合。
// !     - SPP(bit8): sret 返回的目标特权级（0->U, 1->S）
// !     - SPIE/SIE: 中断使能相关
// !     - SUM(bit18): S 模式是否允许访问 U 页
// !   - sscratch: 常用来保存"trap 入口交换栈/上下文指针"。
// !   - satp: 当前页表根与模式（Sv39）。切换进程时会变。
// !   - time: 当前硬件计时器值，用于重设下一次 timer 中断触发点。
// !
// ! scause 常见分类：
// ! - Exception::UserEnvCall: 用户态 ecall（系统调用）
// ! - Exception::{Instruction,Load,Store}PageFault: 页错误（常可恢复）
// ! - Exception::{Load,Store}Fault: 访问错误（通常不可恢复）
// ! - Interrupt::SupervisorTimer: S 态时钟中断
// ! - Interrupt::SupervisorExternal: S 态外部中断
// !
// ! 采用 Direct stvec 模式：所有 trap 先进入同一个汇编入口再分发。

#![allow(unreachable_code)]

mod context;

use core::arch::global_asm;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use riscv::register::{
    mtvec::TrapMode,
    scause::{self, Exception, Interrupt, Trap},
    sstatus, stval, stvec,
};

pub use context::TrapContext;
global_asm!(include_str!("trap.S"));

static IN_KERNEL_TRAP: AtomicBool = AtomicBool::new(false);
static LAST_SYSCALL_RETURN_SCHED_TIME: AtomicUsize = AtomicUsize::new(0);

const SCOUNTEREN_CY: usize = 1 << 0;
const SCOUNTEREN_TM: usize = 1 << 1;
const SCOUNTEREN_IR: usize = 1 << 2;
const SYS_RT_SIGRETURN: usize = 139;
const SYS_EXECVE: usize = 221;

// 这里 panic/trap 处理时不使用普通println! 直接走 SBI ，普通日志路径可能不安全
fn raw_console_puts(s: &str) {
    for b in s.bytes() {
        crate::arch::sbi::console_putchar(b as usize);
    }
}

fn raw_console_puthex(mut value: usize) {
    const HEX: &[u8; 16] = b"0123456789abcdef";
    let mut buf = [0u8; 2 + core::mem::size_of::<usize>() * 2];
    buf[0] = b'0';
    buf[1] = b'x';
    for i in (2..buf.len()).rev() {
        buf[i] = HEX[value & 0xf];
        value >>= 4;
    }
    for b in buf {
        crate::arch::sbi::console_putchar(b as usize);
    }
}

fn raw_console_putln(label: &str, value: usize) {
    raw_console_puts(label);
    raw_console_puthex(value);
    raw_console_puts("\n");
}

#[inline]
/// 初始化 Trap 处理入口和中断相关寄存器。
pub fn init() {
    unsafe extern "C" {
        fn __alltraps();
    }
    unsafe {
        let trap_entry = usize::from(crate::mm::kernel_symbol_to_virt_addr(
            __alltraps as *const () as usize,
        ));
        stvec::write(trap_entry, TrapMode::Direct);
        // 设置 SUM 位（bit 18），允许 S 模式访问 U 模式页面
        sstatus::set_sum();
        // 允许 U 模式读取 cycle/time/instret 计数器，避免部分用户态 libc 路径触发非法指令。
        core::arch::asm!("csrw scounteren, {}", in(reg) (SCOUNTEREN_CY | SCOUNTEREN_TM | SCOUNTEREN_IR));
    }
}

/// 处理内核态 trap，print and 关机。
/// 参数：scause/stval/sepc/ra: trap 原因、附加值、触发 PC 和返回地址现场。
#[unsafe(no_mangle)]
pub extern "C" fn kernel_trap_handler(scause: usize, stval: usize, sepc: usize, ra: usize) -> ! {
    use crate::arch::sbi::shutdown;

    // 检测是否是递归trap
    if IN_KERNEL_TRAP
        .compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst)
        .is_err()
    {
        raw_console_puts("\n[KERNEL PANIC] Recursive trap in kernel mode!\n");
        raw_console_putln("  scause = ", scause);
        raw_console_putln("  stval  = ", stval);
        raw_console_putln("  sepc   = ", sepc);
        raw_console_putln("  ra     = ", ra);
        shutdown(false);
    }

    raw_console_puts("\n[KERNEL PANIC] Trap in kernel mode!\n");
    raw_console_putln("  scause = ", scause);
    raw_console_putln("  stval  = ", stval);
    raw_console_putln("  sepc   = ", sepc);
    raw_console_putln("  ra     = ", ra);
    shutdown(false);
}

/// 向当前进程发送信号（用于 page fault/access fault 等可由用户态信号处理的情况）。
/// 如果进程注册了对应信号处理器，将在返回用户态时投递；否则走默认终止。
fn send_fault_signal(signo: i32) {
    let pid = crate::process::current_pid();
    crate::signal::enqueue_pending_signal(pid, signo, true);
}

