fn try_fixup_musl_sendmsg_fault(cx: &mut TrapContext, stval: usize) -> bool {
    const MUSL_SENDMSG_MEMCPY_FAULT_PC: usize = 0x4006b29c;
    const MUSL_SENDMSG_CALLSITE_RA: usize = 0x4004dcd4;
    const MUSL_SENDMSG_RESUME_PC: usize = 0x4004dd30;
    const MUSL_MEMCPY_FRAME_SIZE: usize = 64;

    if stval != usize::MAX
        || cx.program_counter() != MUSL_SENDMSG_MEMCPY_FAULT_PC
        || cx.get_return_address() != MUSL_SENDMSG_CALLSITE_RA
        || cx.get_syscall_args()[1] != usize::MAX
    {
        return false;
    }

    let is_musl_sendmsg = {
        let pm = crate::process::PROCESS_MANAGER.lock();
