            .is_some_and(|p| p.exec_path.contains("/musl/") && p.exec_path.contains("/sendmsg"))
    };
    if !is_musl_sendmsg {
        return false;
    }

    cx.add_user_stack_pointer(MUSL_MEMCPY_FRAME_SIZE);
    cx.set_program_counter(MUSL_SENDMSG_RESUME_PC);
    true
}

