#![allow(dead_code)]

use super::address::PhysPageNum;
use alloc::vec::Vec;
use core::sync::atomic::{AtomicUsize, Ordering};
use spin::Mutex;

/// 物理页帧分配器trait
pub trait FrameAllocator {
    fn alloc(&mut self) -> Option<PhysPageNum>;
    fn dealloc(&mut self, ppn: PhysPageNum);
}

/// 栈式物理页帧分配器
pub struct StackFrameAllocator {
    start: usize,         // 管理区起始物理页号（用于统计）
    current: usize,       // 当前可用的起始物理页号
    end: usize,           // 结束物理页号
    recycled: Vec<usize>, // 回收的页帧栈
    recycled_bitmap: Vec<bool>,
}

impl StackFrameAllocator {
    /// 创建一个空的栈式页帧分配器。
    pub const fn new() -> Self {
        Self {
            start: 0,
            current: 0,
            end: 0,
            recycled: Vec::new(),
            recycled_bitmap: Vec::new(),
        }
    }

    /// 初始化分配器可管理的物理页区间。
    /// 参数：l: 起始物理页号（含）；r: 结束物理页号（不含）。
    pub fn init(&mut self, l: PhysPageNum, r: PhysPageNum) {
        self.start = l.0;
        self.current = l.0;
        self.end = r.0;
        self.recycled.clear();
        self.recycled_bitmap.clear();
        self.recycled_bitmap.resize(r.0.saturating_sub(l.0), false);
    }

    fn recycled_index(&self, ppn: usize) -> Option<usize> {
        if ppn < self.start || ppn >= self.end {
            return None;
        }
        Some(ppn - self.start)
    }

    fn remove_recycled_ppn(&mut self, ppn: usize) {
        if let Some(pos) = self.recycled.iter().position(|&entry| entry == ppn) {
            self.recycled.swap_remove(pos);
        }
    }

    fn alloc_recycled_contiguous(&mut self, pages: usize) -> Option<usize> {
        if pages == 0 {
            return Some(self.start);
        }

        let limit = self.current.saturating_sub(self.start);
        let mut run_start = 0usize;
        let mut run_len = 0usize;
        for idx in 0..limit {
            if self.recycled_bitmap.get(idx).copied().unwrap_or(false) {
                if run_len == 0 {
                    run_start = idx;
                }
                run_len += 1;
                if run_len == pages {
                    let base = self.start + run_start;
                    for ppn in base..base + pages {
                        if let Some(bitmap_idx) = self.recycled_index(ppn) {
                            self.recycled_bitmap[bitmap_idx] = false;
                        }
                        self.remove_recycled_ppn(ppn);
                    }
                    return Some(base);
                }
            } else {
                run_len = 0;
            }
        }
        None
    }

    fn alloc_contiguous(&mut self, pages: usize) -> Option<usize> {
        if pages == 0 {
            return Some(self.current);
        }
        if self.current + pages <= self.end {
            let base = self.current;
            self.current += pages;
            return Some(base);
        }
        self.alloc_recycled_contiguous(pages)
    }
}

impl FrameAllocator for StackFrameAllocator {
    /// 分配物理页帧
    fn alloc(&mut self) -> Option<PhysPageNum> {
        // 优先从回收栈中分配
        if let Some(ppn) = self.recycled.pop() {
            if let Some(idx) = self.recycled_index(ppn) {
                if let Some(mark) = self.recycled_bitmap.get_mut(idx) {
                    *mark = false;
                }
            }
            Some(ppn.into())
        } else if self.current < self.end {
            // 从未分配区域分配
            let ppn = self.current;
            self.current += 1;
            Some(ppn.into())
        } else {
            // 内存耗尽
            None
        }
    }

    /// 回收物理页帧
    fn dealloc(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.0;
        // 跳过不在管理范围内或已回收的页帧
        if ppn < self.start || ppn >= self.current {
            return;
        }
        let Some(idx) = self.recycled_index(ppn) else {
            return;
        };
        if self.recycled_bitmap.get(idx).copied().unwrap_or(true) {
            return;
        }
        // 加入回收栈
        self.recycled_bitmap[idx] = true;
        self.recycled.push(ppn);
    }
}

/// 全局物理页帧分配器（使用Mutex保护）
static FRAME_ALLOCATOR: Mutex<StackFrameAllocator> = Mutex::new(StackFrameAllocator::new());
static FRAME_REFCNT: Mutex<Vec<usize>> = Mutex::new(Vec::new()); // 记录物理页帧引用次数
static FRAME_REFCNT_BASE: AtomicUsize = AtomicUsize::new(0);
static FRAME_REFCNT_END: AtomicUsize = AtomicUsize::new(0);
static FRAME_ALLOC_FAIL_STREAK: AtomicUsize = AtomicUsize::new(0);
const FRAME_ALLOC_FAIL_LOG_INTERVAL: usize = 256;
const FRAME_ALLOC_RECLAIM_PAGE_BATCH: usize = 8192;

/// 初始化全局物理页帧分配器。
pub fn init_frame_allocator(l: PhysPageNum, r: PhysPageNum) {
    FRAME_ALLOCATOR.lock().init(l, r);
    FRAME_REFCNT_BASE.store(l.0, Ordering::Relaxed);
    FRAME_REFCNT_END.store(r.0, Ordering::Relaxed);
    let mut refs = FRAME_REFCNT.lock();
    refs.clear();
    refs.resize(r.0.saturating_sub(l.0), 0);
}

#[inline]
fn frame_ref_index(ppn: PhysPageNum) -> Option<usize> {
    let base = FRAME_REFCNT_BASE.load(Ordering::Relaxed);
    let end = FRAME_REFCNT_END.load(Ordering::Relaxed);
    if ppn.0 < base || ppn.0 >= end {
        return None;
    }
    Some(ppn.0 - base)
}

#[inline]
fn set_frame_ref(ppn: PhysPageNum, value: usize) {
    if let Some(idx) = frame_ref_index(ppn) {
        if let Some(slot) = FRAME_REFCNT.lock().get_mut(idx) {
            *slot = value;
        }
    }
}

