/// 地址空间，表示一个进程的完整虚拟内存布局
///
/// 设计上，地址空间 = 页表 + 内存区域集合 + 布局元数据：
/// - 页表和区域集合描述了"已映射了什么"
/// - 布局元数据描述了"各逻辑段在哪里"，供 sys_brk / sys_mmap 等动态管理
pub struct MemorySet {
    /// 多级页表，用于硬件地址翻译
    page_table: PageTable,
    /// 有序内存区域映射：以起始虚拟页号为键，便于按地址范围快速查找
    areas: BTreeMap<VirtPageNum, MapArea>,
    /// COW 额外帧引用：当 fork 后的 COW 页被替换时，新帧需被持有以防提前释放
    cow_extra_frames: Vec<FrameTracker>,
    /// 堆区起始虚拟地址（sys_brk 的下界）
    heap_start: usize,
    /// 堆区当前结束虚拟地址（sys_brk 的当前值 / program break）
    heap_end: usize,
    /// mmap 区域的基地址（mmap 分配的上界起点）
    mmap_base: usize,
    /// mmap 下一次分配的起始地址（线性递增分配游标）
    mmap_next: usize,
    /// 栈守护页底部（不可访问的保护区域，防止栈溢出攻击）
    stack_guard_bottom: usize,
    /// 栈区底部（栈增长方向的起始地址）
    stack_bottom: usize,
    /// 栈区顶部（栈增长方向的结束地址，即初始栈指针位置）
    stack_top: usize,
    /// TLS（线程局部存储）区域底部
    tls_bottom: usize,
    /// TLS（线程局部存储）区域顶部
    tls_top: usize,
    /// RV 用户进程共享全局 KERNEL_SPACE 的 high-half kernel page-table subtree。
    shares_kernel_high_half: bool,
    /// RV 用户进程共享全局 KERNEL_SPACE 的低地址 kernel image identity subtree。
    shares_kernel_identity_image: bool,
}

static MEMORY_SET_CREATED: AtomicUsize = AtomicUsize::new(0);
static MEMORY_SET_DROPPED: AtomicUsize = AtomicUsize::new(0);
static MEMORY_SET_DROP_PT_FRAMES: AtomicUsize = AtomicUsize::new(0);

pub fn memory_set_debug_counts() -> (usize, usize, usize) {
    (
        MEMORY_SET_CREATED.load(Ordering::Relaxed),
        MEMORY_SET_DROPPED.load(Ordering::Relaxed),
        MEMORY_SET_DROP_PT_FRAMES.load(Ordering::Relaxed),
    )
}

impl MemorySet {
    fn from_page_table(page_table: PageTable) -> Self {
        MEMORY_SET_CREATED.fetch_add(1, Ordering::Relaxed);
        Self {
            page_table,
            areas: BTreeMap::new(),
            cow_extra_frames: Vec::new(),
            heap_start: 0,
            heap_end: 0,
            mmap_base: 0,
            mmap_next: 0,
            stack_guard_bottom: 0,
            stack_bottom: 0,
            stack_top: 0,
            tls_bottom: 0,
            tls_top: 0,
            shares_kernel_high_half: false,
            shares_kernel_identity_image: false,
        }
    }

    /// 尝试创建一个空地址空间，页表根页不足时返回 None。
    pub fn try_new_bare() -> Option<Self> {
        Some(Self::from_page_table(PageTable::try_new()?))
    }

    /// 创建一个空地址空间。
    ///
    /// 所有布局字段初始化为 0，页表和区域集合为空。
    /// 后续通过 `init_user_layout` 或 `copy_user_layout_from` 填充布局。
    pub fn new_bare() -> Self {
        Self::try_new_bare().expect("MemorySet::new_bare: page-table allocation failed")
    }

    /// 从 `UserVmLayout` 布局模板初始化用户空间各段边界。
    ///
    /// 用于**新进程**创建时，按布局蓝图设定地址空间骨架。
    /// 注意：`mmap_next` 被重置为 `mmap_base`（而非继承模板值），
    /// 表示 mmap 区域从基地址开始线性分配，这是全新进程的正确语义。
    pub fn init_user_layout(&mut self, layout: UserVmLayout) {
        self.heap_start = layout.heap_start;
        self.heap_end = layout.heap_end;
        self.mmap_base = layout.mmap_base;
        self.mmap_next = layout.mmap_base;
        self.stack_guard_bottom = layout.stack_guard_bottom;
        self.stack_bottom = layout.stack_bottom;
        self.stack_top = layout.stack_top;
        self.tls_bottom = layout.tls_bottom;
        self.tls_top = layout.tls_top;
    }

    /// 从另一个 `MemorySet` 复制用户空间布局。
    ///
    /// 用于 **fork** 场景：子进程需继承父进程当前的布局状态。
    /// 与 `init_user_layout` 的关键区别在于：`mmap_next` 直接复制父进程值，
    /// 而非重置为 `mmap_base`，以保证子进程后续 mmap 行为与父进程一致。
    pub fn copy_user_layout_from(&mut self, other: &MemorySet) {
        self.heap_start = other.heap_start;
        self.heap_end = other.heap_end;
        self.mmap_base = other.mmap_base;
        self.mmap_next = other.mmap_next;
        self.stack_guard_bottom = other.stack_guard_bottom;
        self.stack_bottom = other.stack_bottom;
        self.stack_top = other.stack_top;
        self.tls_bottom = other.tls_bottom;
        self.tls_top = other.tls_top;
    }

    // ---- 布局字段 getter ----

    #[inline]
    pub fn heap_start(&self) -> usize {
        self.heap_start
    }

    #[inline]
    pub fn heap_end(&self) -> usize {
        self.heap_end
    }

    #[inline]
    pub fn mmap_base(&self) -> usize {
        self.mmap_base
    }

    #[inline]
    pub fn mmap_next(&self) -> usize {
        self.mmap_next
    }

    #[inline]
    pub fn stack_guard_bottom(&self) -> usize {
        self.stack_guard_bottom
    }

    #[inline]
    pub fn stack_bottom(&self) -> usize {
        self.stack_bottom
    }

    #[inline]
    pub fn stack_top(&self) -> usize {
        self.stack_top
    }

    // ---- 布局字段 setter ----

    #[inline]
    pub fn set_heap_start(&mut self, value: usize) {
        self.heap_start = value;
    }

    #[inline]
    pub fn set_heap_end(&mut self, value: usize) {
        self.heap_end = value;
    }

    #[inline]
    pub fn set_mmap_next(&mut self, value: usize) {
        self.mmap_next = value;
    }

    #[inline]
    pub fn set_mmap_base(&mut self, value: usize) {
        self.mmap_base = value;
    }

    /// 将当前布局反向构造为 `UserVmLayout`，供其他组件使用。
    pub fn user_layout(&self) -> UserVmLayout {
        UserVmLayout {
            stack_guard_bottom: self.stack_guard_bottom,
            stack_bottom: self.stack_bottom,
            stack_top: self.stack_top,
            heap_start: self.heap_start,
            heap_end: self.heap_end,
            mmap_base: self.mmap_base,
            tls_bottom: self.tls_bottom,
            tls_top: self.tls_top,
        }
    }

    /// 获取构造的页表 token（可写入 satp）。
    #[allow(dead_code)]
    pub fn token(&self) -> usize {
        self.page_table.token()
    }

    pub fn debug_page_table_frame_count(&self) -> usize {
        self.page_table.debug_frame_count()
    }

    pub(super) fn mark_shared_kernel_high_half(&mut self) {
        self.shares_kernel_high_half = true;
    }

    pub(super) fn mark_shared_kernel_identity_image(&mut self) {
        self.shares_kernel_identity_image = true;
    }

    #[inline]
    fn root_index_span_bytes() -> usize {
