// TrapContext 在页的末尾，前面是内核栈。
pub const KERNEL_STACK_SIZE: usize = PAGE_SIZE - core::mem::size_of::<TrapContext>();
pub const TRAP_CONTEXT_OFFSET: usize = KERNEL_STACK_SIZE; // TrapContext 在页内的偏移

/// 进程状态
#[derive(Clone, Copy, PartialEq, Debug)]
pub enum ProcessState {
    Ready,
    Running,
    Blocked,
    Zombie,
}

/// 进程控制块
pub struct ProcessControlBlock {
    pub pid: usize,                    // 线程 ID
    pub group: Arc<ThreadGroupShared>, // 线程组级共享身份信息
    pub exec_path: String,             // 当前可执行文件路径
    pub state: ProcessState,           // 当前进程状态
    pub exit_code: i32,                // 线程退出码（组长最终对 wait4 可见）
    pub memory_set: SharedMemorySet,   // 共享用户地址空间句柄
    pub trap_cx_frame: FrameTracker,   // 线程私有 TrapContext 页帧
    pub used_fpu: bool,                // 是否已经按需启用过浮点上下文
    pub fpu_euen_bits: usize,          // LoongArch EUEN 扩展位；其他架构保持 0。
    pub fd_table: SharedFiles,         // 共享文件描述符表
    pub fs_context: SharedFsContext,   // 共享路径解析上下文
    pub signal_shared: SharedSignal,   // 共享信号处理状态
    pub sysvsem: SharedSysvsem,        // 共享 SysV SEM 占位状态
    pub clear_child_tid: usize,        // 线程退出时清零并唤醒 futex 的地址
    pub robust_list_head: usize,       // robust futex 链表头地址
    pub robust_list_len: usize,        // robust futex 头结构长度
    pub sched_policy: isize,           // Linux 调度策略（SCHED_*）
    pub sched_priority: i32,           // 调度优先级（RT 策略使用）
    pub sched_runtime: u64,            // SCHED_DEADLINE runtime，占位保存给 sched_getattr
    pub sched_deadline: u64,           // SCHED_DEADLINE deadline，占位保存给 sched_getattr
    pub sched_period: u64,             // SCHED_DEADLINE period，占位保存给 sched_getattr
}

impl ProcessControlBlock {
    /// 返回线程组号。
    pub fn tgid(&self) -> usize {
        self.group.tgid()
    }

    /// 返回线程组长 tid。
    pub fn leader_pid(&self) -> usize {
        self.group.leader_pid()
    }

    /// 返回父线程组号。
    pub fn parent_pid(&self) -> Option<usize> {
        self.group.parent_pid()
    }

    /// 判断当前线程是否为线程组长。
    pub fn is_group_leader(&self) -> bool {
        self.pid == self.leader_pid()
    }

    /// 获取 TrapContext
    pub fn get_trap_cx(&self) -> &'static mut TrapContext {
        let page_start = self.trap_cx_frame.ppn.get_bytes_array();
        unsafe { &mut *(page_start.as_ptr().add(TRAP_CONTEXT_OFFSET) as *mut TrapContext) }
    }

    /// 获取页表 token
    pub fn get_token(&self) -> usize {
        self.memory_set.token()
    }
}

/// 分配线程私有 trap context 帧。
/// 返回值：成功时返回清零后的页帧跟踪器，失败返回 None。
pub fn alloc_trap_context_frame() -> Option<FrameTracker> {
    frame_alloc()
}

//! 负责进程表、PID 分配、ready queue、当前进程切换和僵尸进程回收入口。

use super::current::{clear_current_fast_cache, update_current_fast_cache};
use super::pcb::{ProcessControlBlock, ProcessState};
use super::recycle::{RECYCLED_PROCESSES, mark_recycle_work};
use alloc::collections::{BTreeSet, VecDeque};
use alloc::string::String;
use alloc::vec::Vec;
use lazy_static::lazy_static;
use spin::Mutex;

lazy_static! {
    pub static ref PROCESS_MANAGER: Mutex<ProcessManager> = Mutex::new(ProcessManager::new());
}

/// 进程管理器
pub struct ProcessManager {
    next_pid: usize,
    current_pid: Option<usize>,
    pub processes: Vec<Option<ProcessControlBlock>>,
    ready_queue: VecDeque<usize>,
    /// 与 ready_queue 镜像的集合，用于 O(log n) 判重，避免 O(n) iter().any()。
    ready_set: BTreeSet<usize>,
    free_pids: Vec<usize>,
}

impl ProcessManager {
    #[inline]
    fn is_ready_pid(&self, pid: usize) -> bool {
        self.processes
            .get(pid)
            .and_then(|p| p.as_ref())
            .map(|pcb| pcb.state == ProcessState::Ready)
            .unwrap_or(false)
    }

    /// 在所有进程槽位里扫描第一个 Ready 进程，并且可选地跳过一个指定 PID。
    #[inline]
    fn scan_ready_pid_except(&self, exclude_pid: Option<usize>) -> Option<usize> {
        self.processes.iter().enumerate().find_map(|(pid, p)| {
            if Some(pid) == exclude_pid {
                return None;
            }
            let pcb = p.as_ref()?;
            if pcb.state == ProcessState::Ready {
                Some(pid)
            } else {
                None
            }
        })
    }

    #[inline]
    fn scan_ready_same_tgid_except(&self, tgid: usize, exclude_pid: usize) -> Option<usize> {
        self.processes.iter().enumerate().find_map(|(pid, p)| {
            if pid == exclude_pid {
                return None;
            }
            let pcb = p.as_ref()?;
            if pcb.tgid() == tgid && pcb.state == ProcessState::Ready {
                Some(pid)
            } else {
                None
            }
        })
    }

    #[inline]
    fn rt_priority_rank(pcb: &ProcessControlBlock) -> Option<i32> {
        match pcb.sched_policy {
            // Linux SCHED_FIFO/SCHED_RR priorities are 1..99.  SCHED_DEADLINE
            // is not fully implemented here, but it should still outrank
            // normal SCHED_OTHER tasks once it is runnable.
            1 | 2 => Some(pcb.sched_priority),
            6 => Some(100),
            _ => None,
        }
    }

    #[inline]
    fn scan_ready_rt_pid_except(&self, exclude_pid: usize) -> Option<usize> {
        let mut best: Option<(usize, i32)> = None;
        for (pid, pcb_opt) in self.processes.iter().enumerate() {
            if pid == exclude_pid {
                continue;
            }
            let Some(pcb) = pcb_opt.as_ref() else {
                continue;
            };
            if pcb.state != ProcessState::Ready {
                continue;
            }
            let Some(rank) = Self::rt_priority_rank(pcb) else {
                continue;
            };
            if best.is_none_or(|(_, best_rank)| rank > best_rank) {
                best = Some((pid, rank));
            }
        }
        best.map(|(pid, _)| pid)
    }

    #[inline]
    pub fn has_ready_rt_except(&self, exclude_pid: usize) -> bool {
        self.scan_ready_rt_pid_except(exclude_pid).is_some()
    }

    #[inline]
    pub fn has_ready_except(&self, exclude_pid: usize) -> bool {
        self.ready_queue
            .iter()
            .any(|&pid| pid != exclude_pid && self.is_ready_pid(pid))
            || self.scan_ready_pid_except(Some(exclude_pid)).is_some()
    }

    pub fn new() -> Self {
        Self {
            next_pid: 1,
            current_pid: None,
            processes: Vec::new(),
            ready_queue: VecDeque::new(),
            ready_set: BTreeSet::new(),
            free_pids: Vec::new(),
        }
    }

    pub fn alloc_pid(&mut self) -> usize {
        while let Some(pid) = self.free_pids.pop() {
            if pid != 0 && self.processes.get(pid).is_some_and(|slot| slot.is_none()) {
                crate::syscall::remove_uts_namespace_for_tgid(pid);
                crate::syscall::clear_process_runtime_state_for_pid_reuse(pid);
                return pid;
            }
        }

        let pid = self.next_pid;
        self.next_pid += 1;
        crate::syscall::remove_uts_namespace_for_tgid(pid);
        crate::syscall::clear_process_runtime_state_for_pid_reuse(pid);
        pid
    }

    fn compact_trailing_empty_slots(&mut self) {
        while self.processes.last().is_some_and(|slot| slot.is_none()) {
            self.processes.pop();
        }
        self.next_pid = self.processes.len().max(1);
        self.free_pids.retain(|&pid| {
            pid != 0
                && pid < self.next_pid
                && self.processes.get(pid).is_some_and(|slot| slot.is_none())
        });
    }

    pub fn count_live_processes(&self) -> usize {
        self.processes
            .iter()
            .filter(|p| {
                p.as_ref()
                    .is_some_and(|pcb| pcb.state != ProcessState::Zombie)
            })
            .count()
    }

    pub fn count_live_threads_in_tgid(&self, tgid: usize) -> usize {
        self.processes
            .iter()
            .filter(|p| {
                p.as_ref()
                    .is_some_and(|pcb| pcb.tgid() == tgid && pcb.state != ProcessState::Zombie)
            })
            .count()
    }

    pub fn debug_ready_queue_len(&self) -> usize {
        self.ready_queue.len()
    }

    pub fn debug_ready_set_len(&self) -> usize {
        self.ready_set.len()
    }

    pub fn debug_free_pid_count(&self) -> usize {
        self.free_pids.len()
    }

    pub fn debug_process_state_counts(&self) -> (usize, usize, usize, usize) {
        let mut ready = 0usize;
        let mut blocked = 0usize;
        let mut zombie = 0usize;
        let mut running = 0usize;
        for pcb_opt in &self.processes {
            let Some(pcb) = pcb_opt.as_ref() else {
                continue;
            };
            match pcb.state {
                ProcessState::Ready => ready += 1,
                ProcessState::Blocked => blocked += 1,
                ProcessState::Zombie => zombie += 1,
                ProcessState::Running => running += 1,
            }
        }
        (ready, blocked, zombie, running)
    }

    pub fn debug_process_slots_summary(&self) -> (usize, usize, usize) {
        let slots = self.processes.len();
        let occupied = self.processes.iter().filter(|p| p.is_some()).count();
        let live = self
            .processes
            .iter()
            .filter(|p| {
                p.as_ref()
                    .is_some_and(|pcb| pcb.state != ProcessState::Zombie)
            })
            .count();
        (slots, occupied, live)
    }

    pub fn check_thread_limit(&self, tgid: usize) -> bool {
        const MAX_THREADS_PER_PROCESS: usize = 1024;
        const MAX_TOTAL_THREADS: usize = 4096;

        if self.processes.len() < MAX_THREADS_PER_PROCESS {
