}

#[derive(Clone, Copy)]
pub struct ResourceLimits {
    limits: [ResourceLimit; LINUX_RLIMIT_NLIMITS],
    cpu_start_us: u64,
    cpu_soft_signal_sent: bool,
}

impl Default for ResourceLimits {
    fn default() -> Self {
        let unlimited = ResourceLimit::new(RLIM_INFINITY, RLIM_INFINITY);
        let mut limits = [unlimited; LINUX_RLIMIT_NLIMITS];
        limits[RLIMIT_STACK] = ResourceLimit::new(REPORTED_STACK_RLIMIT, REPORTED_STACK_RLIMIT);
        limits[RLIMIT_NOFILE] = ResourceLimit::new(RLIMIT_NOFILE_DEFAULT, RLIMIT_NOFILE_DEFAULT);
        Self {
            limits,
            cpu_start_us: 0,
            cpu_soft_signal_sent: false,
        }
    }
}

impl ResourceLimits {
    pub fn get(&self, resource: usize) -> Option<ResourceLimit> {
        self.limits.get(resource).copied()
    }

    fn set(&mut self, resource: usize, limit: ResourceLimit, now_us: u64) -> bool {
        let Some(slot) = self.limits.get_mut(resource) else {
            return false;
        };
        *slot = limit;
        if resource == RLIMIT_CPU {
            self.cpu_start_us = now_us;
            self.cpu_soft_signal_sent = false;
        }
        true
    }
}

