//! 具体 VFS 文件系统后端
//!
//! 这个模块保存所有可以被 VFS 挂载的后端类型
//! 例如 ramfs tmpfs procfs sysfs devfs ext4fs pipefs
//!
//! syscall 层不应该直接进入这里
//! 正常路径应该是 syscall -> vfs_core::api -> VFS ops -> 具体后端
//!
//! 这里的 registry 只保存文件系统类型
//! 真正的一次挂载实例由 VfsSuperBlock 和 VfsMount 表示

use crate::fs::vfs_core::superblock::{
    VfsFileSystemType, devfs_type, ext4_type, hugetlbfs_type, procfs_type, ramfs_type, sysfs_type,
    tmpfs_type, vfat_type,
};
use crate::uapi::errno::{EEXIST, ENOENT};
use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use core::sync::atomic::{AtomicBool, Ordering};
use spin::Mutex;

pub mod anon_inode;
pub mod devfs;
pub mod ext4fs;
pub mod pipefs;
pub mod procfs;
pub mod ramfs;
pub mod sysfs;

lazy_static::lazy_static! {
    // VFS 文件系统类型注册表
    // key 是用户态和内核 mount 路径使用的文件系统名字
    // value 是该类型的 VfsFileSystemType 其中包含 mount 回调
    //
    // 这里保存的是类型 不是已经挂载的实例
    // 例如 ext4_type 表示 ext4 这种后端能力
    // 真正挂到 / 或 /proc 的对象是 VfsMount
    static ref VFS_FILESYSTEM_TYPES: Mutex<BTreeMap<&'static str, Arc<VfsFileSystemType>>> =
        Mutex::new(BTreeMap::new());
}

// 内置后端是否已经注册
// register_builtin_filesystems 会在多个入口防御式调用
// 这个标志保证重复调用只会有第一次真正插入 registry
static VFS_BUILTIN_FILESYSTEMS_REGISTERED: AtomicBool = AtomicBool::new(false);

// 注册一个文件系统类型
// 用于后续通过名字查找 mount 回调
// 同名后端不能重复注册
pub fn register_filesystem(fs: Arc<VfsFileSystemType>) -> Result<(), isize> {
    let mut registry = VFS_FILESYSTEM_TYPES.lock();
    if registry.contains_key(fs.name) {
        return Err(-EEXIST);
    }
    registry.insert(fs.name, fs);
    Ok(())
}

// 注销一个文件系统类型
// 当前主要是兼容 mount namespace 测试里的 unregister 语义
// builtin 名字会先归一化 例如 procfs 会映射到 proc
pub fn unregister_filesystem(name: &str) -> Result<(), isize> {
    register_builtin_filesystems();
    let canonical = canonical_filesystem_name(name);
    let mut registry = VFS_FILESYSTEM_TYPES.lock();
    if registry.remove(canonical).is_some() {
        Ok(())
    } else {
        Err(-ENOENT)
    }
}

// 按名字查找文件系统类型
// 这里会再次调用 register_builtin_filesystems
// 这是为了让调用者不必关心内置后端是否已经注册
// 由于注册函数是幂等的  这里重复调用不会重复插入
pub fn get_filesystem_type(name: &str) -> Option<Arc<VfsFileSystemType>> {
    register_builtin_filesystems();
    let registry = VFS_FILESYSTEM_TYPES.lock();
    registry
        .get(name)
        .cloned()
        .or_else(|| registry.get(canonical_filesystem_name(name)).cloned())
}

// 注册内置文件系统后端
// 第一次调用会把内置类型插入 registry
// 之后再次调用会直接返回
//
// 当前内置后端包括
// ramfs  当前默认 root 的内存后端
// tmpfs  tmpfs 兼容后端
// procfs  /proc 兼容后端
// devfs  /dev 兼容后端
// sysfs  /sys 兼容后端
// hugetlbfs  huge page 文件系统兼容后端
// vfat  fat 系列名字兼容后端
// ext4  测试盘真实持久化后端
pub fn register_builtin_filesystems() {
    if VFS_BUILTIN_FILESYSTEMS_REGISTERED.swap(true, Ordering::AcqRel) {
        return;
    }

    let builtins = [
        ramfs_type(),
        tmpfs_type(),
        procfs_type(),
        devfs_type(),
        sysfs_type(),
        hugetlbfs_type(),
        vfat_type(),
        ext4_type(),
    ];
    let mut registry = VFS_FILESYSTEM_TYPES.lock();
    for fs in builtins {
        registry.entry(fs.name).or_insert(fs);
    }
}

// 文件系统名字归一化
// 用户态 mount 可能传入多个 Linux 常见别名
// 内核内部尽量映射到当前实际实现的后端名字
fn canonical_filesystem_name(name: &str) -> &str {
    match name {
        "rootfs" => "ramfs",
        "procfs" => "proc",
        "devfs" => "devtmpfs",
        "ext2" | "ext3" => "ext4",
        "fat" | "msdos" => "vfat",
        other => other,
    }
}

//! ext4 文件系统磁盘布局定义
//!
//! 只描述磁盘上的结构和少量解析辅助函数
//! 不负责路径查找 inode 缓存或 VFS 适配

/// 从字节切片中读取一个小端 u16
/// offset 越界时返回 None
fn read_u16_le(bytes: &[u8], offset: usize) -> Option<u16> {
    let end = offset.checked_add(2)?;
    let chunk = bytes.get(offset..end)?;
    Some(u16::from_le_bytes([chunk[0], chunk[1]]))
}

/// 从字节切片中读取一个小端 u32
fn read_u32_le(bytes: &[u8], offset: usize) -> Option<u32> {
    let end = offset.checked_add(4)?;
    let chunk = bytes.get(offset..end)?;
    Some(u32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]))
}

/// ext4 超级块简化版本
/// 这里只保留当前内核实际使用的前部字段
#[repr(C)]
pub struct SuperBlock {
    pub s_inodes_count: u32,       // 0x00: Inode 总数
    pub s_blocks_count: u32,       // 0x04: 块总数
    pub s_r_blocks_count: u32,     // 0x08: 保留块数
    pub s_free_blocks_count: u32,  // 0x0C: 空闲块数
    pub s_free_inodes_count: u32,  // 0x10: 空闲 inode 数
    pub s_first_data_block: u32,   // 0x14: 第一个数据块
    pub s_log_block_size: u32,     // 0x18: 块大小 = 1024 << s_log_block_size
    pub s_log_cluster_size: u32,   // 0x1C: 簇大小
    pub s_blocks_per_group: u32,   // 0x20: 每组块数
    pub s_clusters_per_group: u32, // 0x24: 每组簇数
    pub s_inodes_per_group: u32,   // 0x28: 每组 inode 数
    pub s_mtime: u32,              // 0x2C: 挂载时间
    pub s_wtime: u32,              // 0x30: 写入时间
    pub s_mnt_count: u16,          // 0x34: 挂载次数
    pub s_max_mnt_count: u16,      // 0x36: 最大挂载次数
    pub s_magic: u16,              // 0x38: 魔数 0xEF53
    pub s_state: u16,              // 0x3A: 状态
    pub s_errors: u16,             // 0x3C: 错误处理
    pub s_minor_rev_level: u16,    // 0x3E: 次要版本
    pub s_lastcheck: u32,          // 0x40: 最后检查时间
    pub s_checkinterval: u32,      // 0x44: 检查间隔
    pub s_creator_os: u32,         // 0x48: 创建 OS
    pub s_rev_level: u32,          // 0x4C: 版本
    pub s_def_resuid: u16,         // 0x50: 默认保留 UID
    pub s_def_resgid: u16,         // 0x52: 默认保留 GID
    pub s_first_ino: u32,          // 0x54: 第一个非保留 inode
    pub s_inode_size: u16,         // 0x58: inode 大小
}

impl SuperBlock {
    /// ext4 超级块魔数
    pub const MAGIC: u16 = 0xEF53;

    /// 检查超级块魔数是否有效
    pub fn is_valid(&self) -> bool {
        self.s_magic == Self::MAGIC
    }

    /// 计算文件系统块大小
    ///
    /// ext4 规定块大小为 1024 << s_log_block_size
    pub fn block_size(&self) -> usize {
        1024 << self.s_log_block_size
    }
}

/// ext4 inode 磁盘结构简化版本
#[repr(C)]
#[derive(Clone)]
pub struct Inode {
    pub i_mode: u16,        // 文件模式
    pub i_uid: u16,         // 用户 ID
    pub i_size_lo: u32,     // 文件大小（低32位）
    pub i_atime: u32,       // 访问时间
    pub i_ctime: u32,       // 创建时间
    pub i_mtime: u32,       // 修改时间
    pub i_dtime: u32,       // 删除时间
    pub i_gid: u16,         // 组 ID
    pub i_links_count: u16, // 硬链接数
    pub i_blocks_lo: u32,   // 块数（低32位）
    pub i_flags: u32,       // 标志
    pub i_osd1: u32,        // OS 相关
    pub i_block: [u32; 15], // 数据块指针
    pub i_size_high: u32,   // 文件大小（高32位）
}

impl Inode {
    // inode 使用 extent 树而不是传统 15 个直接间接块指针
    pub const EXT4_EXTENTS_FL: u32 = 0x80000;
    // i_block 区域固定为 15 个 u32
    pub const I_BLOCK_BYTES: usize = 15 * 4;

    /// 获取 inode 对应文件大小
    /// ext4 把 64 位 size 拆成低 32 位和高 32 位
    pub fn size(&self) -> usize {
        ((((self.i_size_high as u64) << 32) | self.i_size_lo as u64).min(usize::MAX as u64))
            as usize
    }

    /// 判断该 inode 是否是目录
    pub fn is_dir(&self) -> bool {
        self.i_mode & 0x4000 != 0
    }

    /// 判断该 inode 是否是普通文件
    pub fn is_file(&self) -> bool {
        self.i_mode & 0x8000 != 0
    }

    /// 判断该 inode 是否启用 extent
    pub fn uses_extents(&self) -> bool {
        self.i_flags & Self::EXT4_EXTENTS_FL != 0
    }

    /// 以字节视角获取 inode 内嵌的 60 字节 block 或 extent 区域
    /// extent 解析函数需要按字节读取 header index leaf
    pub fn i_block_bytes(&self) -> [u8; Self::I_BLOCK_BYTES] {
        let mut bytes = [0u8; Self::I_BLOCK_BYTES];
        for (idx, block) in self.i_block.iter().enumerate() {
            let start = idx * 4;
            bytes[start..start + 4].copy_from_slice(&block.to_le_bytes());
        }
        bytes
    }
}

