/// ext4 把 inode table bitmap 等元数据按 block group 管理
/// 当前实现主要使用 inode table 起始块来定位 inode
#[repr(C)]
pub struct GroupDesc {
    pub bg_block_bitmap_lo: u32,      // 0x00: 块位图块号（低32位）
