fn netperf_trace_signal_process(pid: usize) -> Option<&'static str> {
    if !log::log_enabled!(target: "bench::netperf", log::Level::Trace) {
        return None;
    }
    let pm = PROCESS_MANAGER.lock();
    let pcb = pm.get_process(pid)?;
    if pcb.exec_path.contains("netserver") {
        Some("netserver")
    } else if pcb.exec_path.contains("netperf") {
        Some("netperf")
    } else {
        None
    }
}

fn write_sigtimedwait_info_to_process(
    pid: usize,
    info_ptr: usize,
    signo: i32,
) -> Result<(), isize> {
    if info_ptr == 0 {
        return Ok(());
    }
    let siginfo = take_pending_siginfo(pid, signo).unwrap_or(CompatSigInfo {
        si_signo: signo,
        si_errno: 0,
        si_code: SI_TKILL,
        si_pid: current_tgid() as i32,
        si_uid: 0,
        ..CompatSigInfo::default()
    });
    let bytes = unsafe {
        core::slice::from_raw_parts(
            &siginfo as *const CompatSigInfo as *const u8,
            core::mem::size_of::<CompatSigInfo>(),
        )
    };
    let mut pm = PROCESS_MANAGER.lock();
    let Some(pcb) = pm.get_process_mut(pid) else {
        return Err(-EFAULT);
    };
    if !pcb.memory_set.copy_to_user(info_ptr as *mut u8, bytes) {
        return Err(-EFAULT);
    }
    Ok(())
}

fn finish_sigtimedwait_signal(info: *mut u8, pid: usize, signo: i32) -> isize {
    match write_sigtimedwait_info_to_process(pid, info as usize, signo) {
        Ok(()) => signo as isize,
        Err(e) => e,
    }
}

