/// VirtIO HAL 实现
pub struct VirtioHal;

impl VirtioHal {
    #[inline]
    fn phys_to_virt(paddr: usize) -> usize {
        usize::from(phys_to_kernel_virt_addr(PhysAddr::from(paddr)))
    }

    #[inline]
    fn virt_to_phys(vaddr: usize) -> usize {
        if is_kernel_direct_map_addr(VirtAddr::from(vaddr)) {
            return usize::from(kernel_virt_to_phys_addr(VirtAddr::from(vaddr)));
        }
        if vaddr < PHYS_MEMORY_END {
            return vaddr;
        }
        panic!(
            "VirtIO DMA expects a direct-map or identity-mapped RAM address, got {:#x}",
            vaddr
        );
    }
}

unsafe impl Hal for VirtioHal {
    /// 分配 DMA 内存
    /// 参数：pages: 需要分配的页数；_direction: 传输方向（当前未使用）。
    /// 返回值：DMA 起始物理地址和对应虚拟指针。
    fn dma_alloc(pages: usize, _direction: BufferDirection) -> (usize, NonNull<u8>) {
        let frames = frame_alloc_contiguous(pages).expect("VirtIO DMA allocation failed");
        let ppn_base = frames
            .first()
            .map(|frame| frame.ppn)
            .unwrap_or(PhysPageNum(0));
        for frame in frames {
            core::mem::forget(frame);
        }
        let paddr = ppn_base.addr_begin().0;
        let vaddr = NonNull::new(Self::phys_to_virt(paddr) as *mut u8).unwrap();

        (paddr, vaddr)
    }

    /// 释放 DMA 内存
    /// 参数：paddr: DMA 起始物理地址；_vaddr: 对应虚拟地址；pages: 页数。
    /// 返回值：0 表示成功。
    unsafe fn dma_dealloc(paddr: usize, _vaddr: NonNull<u8>, pages: usize) -> i32 {
        let ppn_base = PhysAddr::from(paddr).floor();
        for i in 0..pages {
            frame_dealloc(PhysPageNum(ppn_base.0 + i));
        }
        0
    }

    /// 将 MMIO 物理地址转换为可访问虚拟地址
    /// 参数：paddr: MMIO 物理地址；_size: 映射大小（当前未使用）。
    /// 返回值：非空的虚拟地址指针。
    unsafe fn mmio_phys_to_virt(paddr: usize, _size: usize) -> NonNull<u8> {
        NonNull::new(paddr as *mut u8).unwrap()
    }

    /// 共享内存，给设备一个它能访问的地址，让设备直接读写内存
    /// 参数：buffer: 共享缓冲区；_direction: 传输方向（当前未使用）。
    /// 返回值：设备可见的物理地址。
    unsafe fn share(buffer: NonNull<[u8]>, _direction: BufferDirection) -> usize {
        let vaddr = buffer.as_ptr() as *mut u8 as usize;
        Self::virt_to_phys(vaddr)
    }

    /// 取消共享
    /// 参数：_paddr: 共享物理地址；_buffer: 缓冲区；_direction: 传输方向。
    unsafe fn unshare(_paddr: usize, _buffer: NonNull<[u8]>, _direction: BufferDirection) {
        // 恒等映射,无需操作
    }
}

/// 释放物理页帧，构造临时FrameTracker { ppn }，使用drop_in_place 触发它的 Drop实现，从而调用 frame_dealloc 释放页帧。
/// 参数：ppn: 需要释放的物理页号。
fn frame_dealloc(ppn: PhysPageNum) {
    unsafe {
        core::ptr::drop_in_place(&mut FrameTracker { ppn } as *mut FrameTracker);
    }
}

