    fn mac_address(&self) -> EthernetAddress;
    fn can_send(&self) -> bool;
    fn can_recv(&self) -> bool;
    fn recycle_recv_buffer(&mut self, recv_buf: NetBufPtr);
    fn recycle_send_buffers(&mut self) -> Result<(), ()>;
    fn send(&mut self, ptr: NetBufPtr);
    fn recv(&mut self) -> Option<NetBufPtr>;
    fn alloc_send_buffer(&mut self, size: usize) -> NetBufPtr;
}

static NET_DEVICE: Mutex<Option<Box<dyn NetDevice>>> = Mutex::new(None);

pub fn init_net_device() {
    let mut slot = NET_DEVICE.lock();
    if slot.is_none() {
        *slot = try_new_virtio_net_device();
    }
}

pub fn take_net_device() -> Option<Box<dyn NetDevice>> {
    init_net_device();
    NET_DEVICE.lock().take()
}

#[cfg(target_arch = "riscv64")]
fn try_new_virtio_net_device() -> Option<Box<dyn NetDevice>> {
    use crate::drivers::block::VirtioHal;
    use core::ptr::NonNull;
    use virtio_drivers::transport::{
        DeviceType, Transport,
        mmio::{MmioTransport, VirtIOHeader},
    };

    const VIRTIO_NET_MMIO: usize = 0x1000_2000;

    unsafe {
        let header = NonNull::new(VIRTIO_NET_MMIO as *mut VirtIOHeader).unwrap();
        let Ok(transport) = MmioTransport::new(header) else {
            return None;
        };
        if transport.device_type() != DeviceType::Network {
            return None;
        }
        if let Some(dev) =
            VirtioNetDevice::<QUEUE_SIZE, VirtioHal, MmioTransport>::try_new(transport)
        {
            return Some(Box::new(dev));
        }
    }
    None
}

