}

pub type NetBufBox = Box<NetBuf>;

pub struct NetBuf {
    header_len: usize,
    packet_len: usize,
    capacity: usize,
    buf_ptr: NonNull<u8>,
    pool_offset: usize,
    pool: Arc<NetBufPool>,
}

unsafe impl Send for NetBuf {}
unsafe impl Sync for NetBuf {}

impl NetBuf {
    fn slice(&self, start: usize, len: usize) -> &[u8] {
        unsafe { core::slice::from_raw_parts(self.buf_ptr.as_ptr().add(start), len) }
    }

    fn slice_mut(&mut self, start: usize, len: usize) -> &mut [u8] {
        unsafe { core::slice::from_raw_parts_mut(self.buf_ptr.as_ptr().add(start), len) }
    }

    fn raw_mut_buf(&mut self) -> &mut [u8] {
        self.slice_mut(0, self.capacity)
    }

    fn packet(&self) -> &[u8] {
        self.slice(self.header_len, self.packet_len)
    }

    fn packet_mut(&mut self) -> &mut [u8] {
        self.slice_mut(self.header_len, self.packet_len)
    }

    fn packet_with_header(&self) -> &[u8] {
        self.slice(0, self.header_len + self.packet_len)
    }

    fn set_header_len(&mut self, header_len: usize) {
        debug_assert!(header_len + self.packet_len <= self.capacity);
        self.header_len = header_len;
    }

    fn set_packet_len(&mut self, packet_len: usize) {
        debug_assert!(self.header_len + packet_len <= self.capacity);
        self.packet_len = packet_len;
    }

    pub fn from_ptr(ptr: NetBufPtr) -> NetBufBox {
        unsafe { Box::from_raw(ptr.netbuf_ptr.as_ptr() as *mut NetBuf) }
    }

    pub fn into_ptr(mut self: NetBufBox) -> NetBufPtr {
        let packet_ptr = self.packet_mut().as_mut_ptr();
        let packet_len = self.packet_len;
        NetBufPtr {
            netbuf_ptr: NonNull::new(Box::into_raw(self) as *mut u8).unwrap(),
            packet_ptr: NonNull::new(packet_ptr).unwrap(),
            packet_len,
        }
    }
}

impl Drop for NetBuf {
    fn drop(&mut self) {
        self.pool.dealloc(self.pool_offset);
    }
}

#[derive(Clone, Copy)]
pub struct NetBufPtr {
    netbuf_ptr: NonNull<u8>,
    packet_ptr: NonNull<u8>,
    packet_len: usize,
}

impl NetBufPtr {
    pub fn packet(&self) -> &[u8] {
        unsafe { core::slice::from_raw_parts(self.packet_ptr.as_ptr(), self.packet_len) }
    }

    pub fn packet_mut(&mut self) -> &mut [u8] {
        unsafe { core::slice::from_raw_parts_mut(self.packet_ptr.as_ptr(), self.packet_len) }
    }
}

pub struct NetBufPool {
    buf_len: usize,
    // Fixed-size buffer pool: VirtIO descriptors keep raw pointers into this Vec,
    // so individual buffers are recycled by offset instead of reallocating packets.
    pool: Vec<u8>,
    free_list: Mutex<Vec<usize>>,
}

impl NetBufPool {
    fn new(capacity: usize, buf_len: usize) -> Arc<Self> {
        let pool = vec![0; capacity * buf_len];
        let mut free_list = Vec::with_capacity(capacity);
        for i in 0..capacity {
            free_list.push(i * buf_len);
        }
        Arc::new(Self {
            buf_len,
            pool,
            free_list: Mutex::new(free_list),
        })
    }

    fn alloc(self: &Arc<Self>) -> NetBuf {
        let offset = self
            .free_list
            .lock()
            .pop()
            .expect("net buffer pool exhausted");
        let buf_ptr = NonNull::new(unsafe { self.pool.as_ptr().add(offset) as *mut u8 }).unwrap();
        NetBuf {
            header_len: 0,
            packet_len: 0,
            capacity: self.buf_len,
            buf_ptr,
            pool_offset: offset,
            pool: Arc::clone(self),
        }
    }

    fn dealloc(&self, offset: usize) {
        debug_assert!(offset % self.buf_len == 0);
        self.free_list.lock().push(offset);
    }
}

