# Top-level orchestrator Makefile
# - OS/os/Makefile handles kernel build details
# - OS/user/Makefile handles user build details

KERNEL_DIR := os
USER_DIR := user
KERNEL_RV := kernel-rv
KERNEL_LA := kernel-la

MODE ?= release
LOG ?=
LOG_TARGET ?=
# show 模式用于演示：用户态不启用 auto_test，但内核仍用 release 产物
ifeq ($(MODE),show)
KERNEL_MODE := release
else
KERNEL_MODE := $(MODE)
endif

KERNEL_RV_ELF := $(KERNEL_DIR)/target/riscv64gc-unknown-none-elf/$(KERNEL_MODE)/os
KERNEL_LA_ELF := $(KERNEL_DIR)/target/loongarch64-unknown-none/$(KERNEL_MODE)/os

ARCH_TEST ?=
DISK_IMG_RV ?= ../sdcard-rv.img
DISK_IMG_LA ?= ../sdcard-la.img


.PHONY: all kernel-rv kernel-la clean help

all: kernel-rv kernel-la
	@echo "[make] build done: $(KERNEL_RV) + $(KERNEL_LA) (MODE=$(MODE))"

kernel-rv:
	@echo "[make] build done: $(KERNEL_RV) + user (MODE=$(MODE))"
	@$(MAKE) -C "$(USER_DIR)" build ARCH=riscv64 MODE="$(MODE)"
	@$(MAKE) -C "$(KERNEL_DIR)" ARCH=riscv64 MODE="$(KERNEL_MODE)" USER_MODE="$(MODE)" LOG="$(LOG)" LOG_TARGET="$(LOG_TARGET)"
	@cp "$(KERNEL_RV_ELF)" "$(KERNEL_RV)"
	@echo "[make] copied $(KERNEL_RV_ELF) -> $(KERNEL_RV)"


kernel-la:
	@echo "[make] build done: $(KERNEL_LA) + user (MODE=$(MODE))"
	@$(MAKE) -C "$(USER_DIR)" build ARCH=loongarch64 MODE="$(MODE)"
	@$(MAKE) -C "$(KERNEL_DIR)" ARCH=loongarch64 MODE="$(KERNEL_MODE)" USER_MODE="$(MODE)" LOG="$(LOG)" LOG_TARGET="$(LOG_TARGET)"
	@cp "$(KERNEL_LA_ELF)" "$(KERNEL_LA)"
	@echo "[make] copied $(KERNEL_LA_ELF) -> $(KERNEL_LA)"


clean:
	@echo "[make] cleaning"
	@$(MAKE) -C "$(KERNEL_DIR)" clean
	@$(MAKE) -C "$(USER_DIR)" clean
	@rm -f "$(KERNEL_RV)"
	@rm -f "$(KERNEL_LA)"
	@echo "[make] clean done"

help:
	@echo "Targets:"
	@echo "  all         Build kernel-rv + kernel-la (default)"
	@echo "  kernel-rv   Build riscv64 kernel + user and copy to ./kernel-rv"
	@echo "  kernel-la   Build loongarch64 kernel + user and copy to ./kernel-la"
	@echo "  clean       Remove build artifacts"
