use core::sync::atomic::{AtomicUsize, Ordering};

use super::VirtPageNum;

pub const SWAP_ENABLED: bool = false;

static PAGE_FAULT_TOTAL: AtomicUsize = AtomicUsize::new(0);
static COW_BREAK_TOTAL: AtomicUsize = AtomicUsize::new(0);
static LAZY_ALLOC_TOTAL: AtomicUsize = AtomicUsize::new(0);
static SWAP_OUT_TOTAL: AtomicUsize = AtomicUsize::new(0);
static SWAP_IN_TOTAL: AtomicUsize = AtomicUsize::new(0);

/// 记录一次页错误事件。
pub fn on_page_fault() {
    PAGE_FAULT_TOTAL.fetch_add(1, Ordering::Relaxed);
}

/// 记录一次 COW 拆分事件。
pub fn on_cow_break() {
    COW_BREAK_TOTAL.fetch_add(1, Ordering::Relaxed);
}

/// 记录一次按需分配事件。
pub fn on_lazy_alloc() {
    LAZY_ALLOC_TOTAL.fetch_add(1, Ordering::Relaxed);
}

/// 记录一次换出事件。
/// 参数：_vpn: 发生换出的虚拟页号（当前仅用于接口占位）。
pub fn on_swap_out(_vpn: VirtPageNum) {
    SWAP_OUT_TOTAL.fetch_add(1, Ordering::Relaxed);
}

/// 记录一次换入事件。
/// 参数：_vpn: 发生换入的虚拟页号（当前仅用于接口占位）。
pub fn on_swap_in(_vpn: VirtPageNum) {
    SWAP_IN_TOTAL.fetch_add(1, Ordering::Relaxed);
}

/// 打印当前内存管理统计信息。
pub fn dump_stats() {
    println!(
        "[mm-stats] pf={} cow={} lazy={} swap_out={} swap_in={} enabled={}",
        PAGE_FAULT_TOTAL.load(Ordering::Relaxed),
        COW_BREAK_TOTAL.load(Ordering::Relaxed),
        LAZY_ALLOC_TOTAL.load(Ordering::Relaxed),
        SWAP_OUT_TOTAL.load(Ordering::Relaxed),
        SWAP_IN_TOTAL.load(Ordering::Relaxed),
        SWAP_ENABLED
    );
}

