/// 在 exec 之前把当前线程组收敛成单线程。
fn collapse_thread_group_for_exec(
    pm: &mut ProcessManager,
    current_pid: usize,
) -> Option<(Option<usize>, u8)> {
    let (tgid, parent_pid, exit_signal, old_group) = {
        let current = pm.get_process(current_pid)?;
        (
            current.tgid(),
            current.parent_pid(),
            current.group.exit_signal(),
            current.group.clone(),
        )
    };

    let mut peers: Vec<usize> = Vec::new();
    for (pid, pcb_opt) in pm.processes.iter().enumerate() {
        let Some(pcb) = pcb_opt.as_ref() else {
            continue;
        };
        if pid != current_pid && pcb.tgid() == tgid {
            peers.push(pid);
        }
    }

    // Linux exec 会摧毁同线程组内除调用线程外的其他线程。这里直接回收 peer PCB，
    // 然后为当前线程建立新的线程组共享状态，保留必要的 rlimit/job-control 属性。
    for pid in peers {
        pm.remove_from_ready(pid);
        pm.recycle_process(pid);
    }

    let current = pm.get_process_mut(current_pid)?;
    let group = Arc::new(ThreadGroupShared::new(
        current_pid,
        current_pid,
        parent_pid,
        exit_signal,
    ));
    group.inherit_resource_limits_from(&old_group);
    group.inherit_job_control_from(&old_group);
    group.inherit_credentials_from(&old_group);
    group.inherit_process_attrs_from_exec(&old_group);
    group.inherit_rusage_from_exec(&old_group);
    current.group = group;
    Some((parent_pid, exit_signal))
}

/// 从路径加载并执行程序。
pub fn exec_from_path(path: &str) -> ! {
    let elf_data =
        read_exec_image(path).expect(&alloc::format!("Failed to load program: {}", path));
    let (memory_set, user_sp, entry_point, layout) = create_user_memory(&elf_data);
    let memory_set = SharedMemorySet::new(memory_set);
    let trap_cx_frame = alloc_trap_context_frame().expect("Failed to allocate trap context frame");

    let pid = {
        let mut pm = PROCESS_MANAGER.lock();
        let pid = pm.alloc_pid();
        let cwd = if let Some(pos) = path.rfind('/') {
            let dir = &path[..pos];
            if dir.is_empty() {
                "/".to_string()
            } else {
                dir.to_string()
            }
        } else {
            "/".to_string()
        };
        let pcb = ProcessControlBlock {
            pid,
            group: Arc::new(ThreadGroupShared::new(pid, pid, None, 0)),
            exec_path: path.to_string(),
            state: ProcessState::Ready,
            exit_code: 0,
            memory_set,
            trap_cx_frame,
            used_fpu: false,
            fpu_euen_bits: 0,
            fd_table: SharedFiles::new(FdTable::new()),
            fs_context: SharedFsContext::new(FsContext::new(cwd)),
            signal_shared: SharedSignal::new(SignalShared::default()),
            sysvsem: SharedSysvsem::new(SysvsemShared::default()),
            clear_child_tid: 0,
            robust_list_head: 0,
            robust_list_len: 0,
            sched_policy: 0,
            sched_priority: 0,
            sched_runtime: 0,
            sched_deadline: 0,
            sched_period: 0,
        };
        pm.add_process(pcb);
        pm.set_current(pid);
        pid
    };
    let _ = pid;

    {
        let pm = PROCESS_MANAGER.lock();
        if let Some(pcb) = pm.current_process() {
            pcb.memory_set.activate();
        }
    }

    {
        let mut pm = PROCESS_MANAGER.lock();
        let pcb = pm.current_process_mut().unwrap();
        write_user_usize(&pcb.memory_set, user_sp, 0);
    }

    let trap_cx_frame = {
        let pm = PROCESS_MANAGER.lock();
        pm.current_process().unwrap().trap_cx_frame.ppn
    };
    let page_start_pa = trap_cx_frame.get_bytes_array();
    let trap_cx =
        unsafe { &mut *(page_start_pa.as_ptr().add(TRAP_CONTEXT_OFFSET) as *mut TrapContext) };
    init_user_entry_context(
        trap_cx,
        entry_point,
        user_sp,
        0,
        initial_thread_pointer(
            &{
                let pm = PROCESS_MANAGER.lock();
                pm.current_process().unwrap().memory_set.clone()
            },
            layout,
            &elf_data,
            None,
            path,
            None,
        ),
    );

    drop(elf_data);

    let token = {
        let pm = PROCESS_MANAGER.lock();
        pm.current_process().unwrap().get_token()
    };
    enter_first_user_mode(trap_cx as *const TrapContext, token, entry_point);
}

