pub(crate) fn wake_vfork_parent(child_pid: usize) -> bool {
    let parent_pid = {
        let mut waiters = VFORK_WAITERS.lock();
        waiters.remove(&child_pid)
    };
    let Some(parent_pid) = parent_pid else {
        return false;
    };
    let mut pm = PROCESS_MANAGER.lock();
    let Some(parent) = pm.get_process(parent_pid) else {
        return false;
    };
    if parent.state == ProcessState::Blocked {
        pm.push_ready_front(parent_pid);
        true
    } else {
        false
    }
}

