#[inline]
fn should_trace_target_thread_clone(exec_path: &str) -> bool {
    cfg!(target_arch = "loongarch64") && exec_path.contains("entry-static.exe")
}

#[inline]
fn should_run_fork_child_first(
    _exec_path: &str,
    flags: CloneFlags,
    vfork_wait: bool,
    ready_pressure: bool,
) -> bool {
    // A forked child is a newly woken task.  Linux's wakeup preemption prevents
    // it from being buried behind a long run queue, but small fork groups should
    // keep normal FIFO fairness.  Only give regular fork children one direct
    // turn when the system is already under clear task pressure.  vfork keeps
    // its dedicated parent-blocking path, and CLONE_THREAD is handled below.
    ready_pressure && !vfork_wait && !flags.contains(CloneFlags::THREAD)
}

#[inline]
fn should_run_thread_child_once(_exec_path: &str, flags: CloneFlags) -> bool {
    // A freshly-created pthread often has to run a short libc trampoline before
    // the parent can observe its TID, clear-child-tid state, or scheduler
    // attributes.  Linux's wakeup preemption can let the child run promptly; on
    // our single-core FIFO scheduler, explicitly give every CLONE_THREAD child
    // one turn so it is not buried behind unrelated ready tasks.
    flags.contains(CloneFlags::THREAD)
}

