/// 在 fork 子进程的地址空间中，清理 glibc TCB 里的多线程残留状态。
///
/// 当父进程经历过 pthread_create/join 后，TCB 中的 `multiple_threads` 标志
/// 和线程链表指针仍指向旧的（已退出的）线程描述符。fork 子进程继承了这些脏字段，
/// 导致 glibc `__fork` 的 child-path 以多线程模式执行清理逻辑，读到陈旧指针后
/// 可能破坏子进程的主线程栈元数据，最终在后续函数调用时产生 user trap。
///
/// 修复策略：在 fork 完成 COW 拷贝之后、子进程被调度之前，把 child 的 TCB 重置
/// 为"单线程进程"应有的状态：
///   1. `multiple_threads` = 0
///   2. 线程链表 list.{next,prev} 指向自身（自环）
///   3. `stackblock` / `stackblock_size` 指向子进程真正的主线程栈
#[cfg(target_arch = "riscv64")]
fn sanitize_riscv_glibc_fork_child_tcb(
    child_memory_set: &crate::process::SharedMemorySet,
    tp: usize,
) {
    if tp < crate::loader::RISCV_GLIBC_TLS_PRE_TCB_SIZE {
        return;
    }
    let thread_self = tp - crate::loader::RISCV_GLIBC_TLS_PRE_TCB_SIZE;

    // 1. multiple_threads = 0 (u32 at thread_self + 0)
    let zero_u32: [u8; 4] = 0u32.to_le_bytes();
    child_memory_set.copy_to_user(thread_self as *mut u8, &zero_u32);

    // 2. Thread list self-loop
    //    list_t lives at thread_self + 0xC0, fields: next (offset 0), prev (offset 8)
    //    For a single-threaded process, both must point to the list_t itself.
    let list_addr = thread_self + 0xC0;
    let list_addr_bytes: [u8; 8] = list_addr.to_le_bytes();
    // list.next = &list  (at thread_self + 0xC0)
    child_memory_set.copy_to_user(list_addr as *mut u8, &list_addr_bytes);
    // list.prev = &list  (at thread_self + 0xC8)
    child_memory_set.copy_to_user((list_addr + 8) as *mut u8, &list_addr_bytes);

    // 3. stackblock / stackblock_size from child's actual stack layout
    let layout = child_memory_set.user_layout();
    let stackblock_bytes: [u8; 8] = layout.stack_bottom.to_le_bytes();
    let stacksize_bytes: [u8; 8] = layout
        .stack_top
        .saturating_sub(layout.stack_bottom)
        .to_le_bytes();
    // stackblock at thread_self + 0x490
    child_memory_set.copy_to_user((thread_self + 0x490) as *mut u8, &stackblock_bytes);
    // stackblock_size at thread_self + 0x498
    child_memory_set.copy_to_user((thread_self + 0x498) as *mut u8, &stacksize_bytes);
}

#[cfg(target_arch = "riscv64")]
fn trace_riscv_glibc_fork_tcb(
    memory_set: &crate::process::SharedMemorySet,
    tp: usize,
    label: &str,
) {
    if tp < crate::loader::RISCV_GLIBC_TLS_PRE_TCB_SIZE {
        return;
    }
    let thread_self = tp - crate::loader::RISCV_GLIBC_TLS_PRE_TCB_SIZE;
    let mt = read_user_u32_slot(memory_set, thread_self);
    let list_prev = read_user_usize_slot(memory_set, tp.wrapping_sub(1696));
    let list_next = read_user_usize_slot(memory_set, tp.wrapping_sub(1688));
    let state = read_user_u8_slot(memory_set, tp.wrapping_sub(846));
    let stackblock = read_user_usize_slot(memory_set, tp.wrapping_sub(0x2d0));
    let stackblock_size = read_user_usize_slot(memory_set, tp.wrapping_sub(0x2c8));
    let layout = memory_set.user_layout();
    log::trace!(
        target: "bench::libcbench::fork",
        "tcb label={} tp={:#x} self={:#x} multi_threads={:?} list_prev={:?} list_next={:?} state={:?} stackblock={:?} stackblock_size={:?} stack=[{:#x},{:#x})",
        label,
        tp,
        thread_self,
        mt,
        list_prev,
        list_next,
        state,
        stackblock,
        stackblock_size,
        layout.stack_bottom,
        layout.stack_top,
    );
}

