#[inline]
fn arm_next_timer_interrupt() {
    // Use the same interval as the kernel-trap timer fast path so
    // the countdown doesn't expire during the handler's UART output.
    let interval = core::cmp::max(
        1,
        crate::arch::timer::get_clock_freq() / crate::arch::config::TIMER_TICK_HZ,
    );
    crate::arch::sbi::set_timer(crate::syscall::next_timeout_deadline_ticks(interval));
}

#[inline]
fn clear_timer_interrupt() {
    unsafe {
        core::arch::asm!("csrwr {value}, 0x44", value = in(reg) 1usize);
    }
}

pub fn defer_next_timer_for_latency_syscall() {
    DEFER_LATENCY_TIMER_ON_RETURN.store(1, Ordering::Relaxed);
}

#[inline]
fn extension_bits_for_ecode(ecode: usize) -> Option<usize> {
    // EUEN bits: 0=FPU, 1=LSX, 2=LASX
    match ecode {
        15 => Some(0x1),
        16 => Some(0x3),
        17 => Some(0x7),
        _ => None,
    }
}

#[inline]
fn enable_user_extension_unit(ecode: usize) -> Option<usize> {
    let bits = extension_bits_for_ecode(ecode)?;

    let mut euen: usize;
    unsafe {
        core::arch::asm!("csrrd {value}, 0x2", value = out(reg) euen);
    }
    if (euen & bits) != bits {
        euen |= bits;
        unsafe {
            core::arch::asm!("csrwr {value}, 0x2", value = in(reg) euen);
        }
    }
    Some(bits)
}

