        0 => "INT",
        1 => "PIL",
        2 => "PIS",
        3 => "PIF",
        4 => "PME",
        5 => "PNR",
        6 => "PNX",
        7 => "PPI",
        11 => "SYS",
        15 => "FPD",
        16 => "SXD",
        17 => "ASXD",
        _ => "UNKNOWN",
    }
}

