/// 从 address_space 找回宿主 inode
fn ext4_inode_from_mapping(mapping: &Arc<VfsAddressSpace>) -> Result<Arc<VfsInode>, isize> {
    vfs_inode_from_key(mapping.host()).ok_or(-EINVAL)
}

/// 读取单个 page
/// page index 转换为文件偏移后从 raw ext4 读取
/// 文件尾部不足一页的部分补零
fn ext4_readpage(mapping: &Arc<VfsAddressSpace>, index: u64) -> Result<Arc<Mutex<VfsPage>>, isize> {
    let inode = ext4_inode_from_mapping(mapping)?;
    let private = ext4_private(&inode)?;
    let page_start = index.checked_mul(PAGE_SIZE as u64).ok_or(-EFBIG)?;
    let offset = usize::try_from(page_start).map_err(|_| -EFBIG)?;
    let page = Arc::new(Mutex::new(VfsPage::new_zeroed(index)));
    {
        let mut guard = page.lock();
        let bytes = guard.bytes_mut();
        let read = crate::fs::ext4::read_at_raw(private.disk_ino, offset, bytes)?;
        if read < bytes.len() {
            bytes[read..].fill(0);
        }
    }
    Ok(page)
}

/// 批量读取 page
///
/// 先一次性从 raw ext4 读取连续字节
/// 再拆成多个 page 放入 address_space
fn ext4_readpages(
    mapping: &Arc<VfsAddressSpace>,
    start_index: u64,
    count: usize,
) -> Result<usize, isize> {
    if count == 0 {
        return Ok(0);
    }
    let inode = ext4_inode_from_mapping(mapping)?;
    let private = ext4_private(&inode)?;
    let page_start = start_index.checked_mul(PAGE_SIZE as u64).ok_or(-EFBIG)?;
    let offset = usize::try_from(page_start).map_err(|_| -EFBIG)?;
    let total_len = count.checked_mul(PAGE_SIZE).ok_or(-EFBIG)?;
    let mut data = vec![0u8; total_len];
    let read = crate::fs::ext4::read_at_raw(private.disk_ino, offset, &mut data)?;
    if read < data.len() {
        data[read..].fill(0);
    }

    let mut loaded = 0usize;
    for page_no in 0..count {
        let Some(index) = start_index.checked_add(page_no as u64) else {
            break;
        };
        // 已经在 page cache 中的页不重复插入
        if mapping.cached_page(index).is_some() {
            continue;
        }
        let page = Arc::new(Mutex::new(VfsPage::new_zeroed(index)));
        {
            let mut guard = page.lock();
            let start = page_no * PAGE_SIZE;
            guard
                .bytes_mut()
                .copy_from_slice(&data[start..start + PAGE_SIZE]);
        }
        crate::fs::vfs_core::debug::vfs_fsstat_note_mapping_page_miss();
        mapping.insert_page(page);
        loaded = loaded.saturating_add(1);
    }
    Ok(loaded)
}

/// 写回单个脏 page
fn ext4_writepage(
    mapping: &Arc<VfsAddressSpace>,
    index: u64,
    _wbc: &VfsWritebackControl,
) -> Result<(), isize> {
    let inode = ext4_inode_from_mapping(mapping)?;
    let private = ext4_private(&inode)?;
    let page_start = index.checked_mul(PAGE_SIZE as u64).ok_or(-EFBIG)?;
    let size = inode.metadata().size;
    let Some(page) = mapping.cached_page(index) else {
        return Ok(());
    };
    let mut guard = page.lock();
    if page_start >= size {
        // page 已经在 EOF 之后
        // 清掉 dirty 即可
        guard.clear_dirty();
        return Ok(());
    }
    let valid_len = (size - page_start).min(PAGE_SIZE as u64) as usize;
    let offset = usize::try_from(page_start).map_err(|_| -EFBIG)?;
    crate::fs::ext4::write_at_raw(private.disk_ino, offset, &guard.bytes()[..valid_len])?;
    guard.clear_dirty();
    Ok(())
}

