macro_rules! net_sys_log {
    ($($arg:tt)*) => {
        log::debug!(target: "net::syscall", $($arg)*);
    };
}

fn netperf_trace_task() -> Option<(usize, &'static str)> {
    if !log::log_enabled!(target: "bench::netperf", log::Level::Trace) {
        return None;
    }
    let pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process()?;
    if pcb.exec_path.contains("netserver") {
        Some((pcb.pid, "netserver"))
    } else if pcb.exec_path.contains("netperf") {
        Some((pcb.pid, "netperf"))
    } else {
        None
    }
}

fn should_trace_sendto_case() -> bool {
    if !log::log_enabled!(target: "net::sendto", log::Level::Trace) {
        return false;
    }
    let pm = PROCESS_MANAGER.lock();
    pm.current_process()
        .is_some_and(|pcb| pcb.exec_path.contains("sendto01") || pcb.exec_path.contains("sendto"))
}

fn should_trace_sendmsg_case() -> bool {
    let pm = PROCESS_MANAGER.lock();
    pm.current_process()
        .is_some_and(|pcb| pcb.exec_path.contains("sendmsg01"))
}

fn trace_net_ret(op: &str, fd: usize, ret: isize) {
    if !log::log_enabled!(target: "bench::netperf", log::Level::Trace) {
        return;
    }
    if ret >= 0 && NETPERF_LOG_COUNT.fetch_add(1, Ordering::Relaxed) >= NETPERF_LOG_LIMIT {
        return;
    }
    if let Some((pid, name)) = netperf_trace_task() {
        log::trace!(
            target: "bench::netperf",
            "proc={} pid={} op={} fd={} ret={}",
            name,
            pid,
            op,
            fd,
            ret
        );
    }
}

fn trace_net_lookup_err(op: &str, fd: usize, err: SocketLookupError) {
    trace_net_ret(op, fd, err.errno());
}

fn trace_net_io(op: &str, fd: usize, len: usize, ret: isize) {
    if !log::log_enabled!(target: "bench::netperf", log::Level::Trace) {
        return;
    }
    let important = ret < 0 || (600..=700).contains(&len);
    if !important && NETPERF_LOG_COUNT.fetch_add(1, Ordering::Relaxed) >= NETPERF_LOG_LIMIT {
        return;
    }
    if let Some((pid, name)) = netperf_trace_task() {
        log::trace!(
            target: "bench::netperf",
            "proc={} pid={} op={} fd={} len={} ret={}",
            name,
            pid,
            op,
            fd,
            len,
            ret
        );
    }
}

fn trace_netperf_response(fd: usize, data: &[u8], ret: isize) {
    if !log::log_enabled!(target: "bench::netperf", log::Level::Trace) {
        return;
    }
    if data.len() < 8 || !(600..=700).contains(&data.len()) {
        return;
    }
    let Some((pid, name)) = netperf_trace_task() else {
        return;
    };
    if name != "netserver" {
        return;
    }
    let response_type = i32::from_be_bytes([data[0], data[1], data[2], data[3]]);
    let serv_errno = i32::from_be_bytes([data[4], data[5], data[6], data[7]]);
    log::trace!(
        target: "bench::netperf",
        "proc={} pid={} op=netperf-response fd={} type={} serv_errno={} ret={}",
        name,
        pid,
        fd,
        response_type,
        serv_errno,
        ret
    );
}

fn blocking_socket_wait_interrupted() -> bool {
    crate::syscall::poll_timers();
    crate::signal::poll_timeouts();
    let pending = crate::signal::current_has_unblocked_pending_signal();
    if pending {
        if let Some((pid, name)) = netperf_trace_task() {
            log::trace!(
                target: "bench::netperf",
                "proc={} pid={} op=socket-eintr",
                name,
                pid
            );
        }
    }
    pending
}

fn with_fd_table<F, R>(f: F) -> R
where
    F: FnOnce(&FdTable) -> R,
{
    let pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process().expect("No current process");
    pcb.fd_table.with(f)
}

fn with_fd_table_mut<F, R>(f: F) -> R
where
    F: FnOnce(&mut FdTable) -> R,
{
    let mut pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process_mut().expect("No current process");
    pcb.fd_table.with_mut(f)
}

fn fd_is_nonblock(fd: usize) -> bool {
    with_fd_table(|fd_table| {
        fd_table
            .get(fd)
            .map(|desc| (desc.flags & O_NONBLOCK) != 0)
            .unwrap_or(false)
    })
}

fn socket_call_nonblock(fd: usize, flags: i32) -> bool {
    fd_is_nonblock(fd) || ((flags & MSG_DONTWAIT) != 0)
}

fn read_user_buffer(ptr: *const u8, len: usize) -> Option<Vec<u8>> {
    if len == 0 {
        return Some(Vec::new());
    }
    let pm = PROCESS_MANAGER.lock();
    let pcb = pm.current_process()?;
    pcb.memory_set.copy_from_user(ptr, len)
}

fn write_user_buffer(ptr: *mut u8, data: &[u8]) -> bool {
    let mut pm = PROCESS_MANAGER.lock();
    let Some(pcb) = pm.current_process_mut() else {
        return false;
    };
    pcb.memory_set.copy_to_user(ptr, data)
}

