//! 负责用户态 page fault 分派和按 VMA 语义补页。

use super::PROCESS_MANAGER;
use crate::arch::config::{MM_DEBUG_LOG, PAGE_SIZE, USER_MAX_VA};
use crate::fs::vfs_core::api as vfs_api;
use crate::mm::{MapPermission, VirtAddr, VmAreaKind};
use alloc::string::String;
use alloc::vec;

const FILE_MMAP_FAULT_RECLAIM_BATCH: usize = 8192;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum UserPageFaultCause {
    Instruction,
    Load,
    Store,
}

#[inline]
fn is_user_va(va: usize) -> bool {
    va != 0 && va <= USER_MAX_VA
}

fn reclaim_current_readonly_file_mmap_pages() -> usize {
    let memory_set = {
        let pm = PROCESS_MANAGER.lock();
        pm.current_process().map(|pcb| pcb.memory_set.clone())
    };
    memory_set
        .map(|memory_set| {
            memory_set.reclaim_readonly_shared_file_mmap_pages(FILE_MMAP_FAULT_RECLAIM_BATCH)
        })
        .unwrap_or(0)
}

/// 页错误分派入口：
/// - 已映射页的权限错误：返回 false（交给上层终止进程）
/// - 未映射但落在合法 VMA 中：按区域语义补页并返回 true
/// - 其余非法地址：返回 false
pub fn handle_user_page_fault(fault_addr: usize, cause: UserPageFaultCause) -> bool {
    crate::mm::swap::on_page_fault();
    if !is_user_va(fault_addr) {
        return false;
    }

    let page_base = fault_addr & !(PAGE_SIZE - 1);
    let vpn = VirtAddr::from(page_base).floor();
    let mut file_fill: Option<(crate::mm::FilePageLoad, MapPermission)> = None;
    let mut debug_exec_path: Option<String> = None;
    let mut pm = PROCESS_MANAGER.lock();

    let anon_or_mapped = {
        let pcb = match pm.current_process_mut() {
            Some(pcb) => pcb,
            None => return false,
        };
        debug_exec_path = Some(pcb.exec_path.clone());

        if let Some(pte) = pcb.memory_set.translate(vpn) {
            #[cfg(not(target_arch = "loongarch64"))]
            let _ = pte;
            if cause == UserPageFaultCause::Store
                && pcb.memory_set.handle_cow_fault(VirtAddr::from(fault_addr))
            {
                crate::mm::swap::on_cow_break();
                if MM_DEBUG_LOG {
                    println!("[mm] COW break: va={:#x}", fault_addr);
                }
                return true;
            }
            #[cfg(target_arch = "loongarch64")]
            {
                let permitted = match cause {
                    UserPageFaultCause::Instruction => pte.executable(),
                    UserPageFaultCause::Load => pte.readable(),
                    UserPageFaultCause::Store => pte.writable(),
                };
                if permitted && pte.user_accessible() {
                    crate::arch::flush_tlb_all();
                    return true;
                }
            }
            // 已映射但仍 fault，多半是权限问题（例如执行不可执行），交给上层杀进程。
            return false;
        }

        let required_perm = match cause {
            UserPageFaultCause::Instruction => MapPermission::X,
            UserPageFaultCause::Load => MapPermission::R,
            UserPageFaultCause::Store => MapPermission::W,
        };

        let Some((area_perm, area_kind)) =
            pcb.memory_set.find_area_info(VirtAddr::from(fault_addr))
        else {
            if pcb
                .memory_set
                .grow_down_page_for_fault(VirtAddr::from(page_base), required_perm)
