pub struct RecycleRuntimeStats {
    pub queued_pcbs: usize,
    pub queued_memsets: usize,
    pub enqueued_pcbs: usize,
    pub enqueued_memsets: usize,
    pub drain_calls: usize,
    pub pressure_calls: usize,
    pub heap_pressure_calls: usize,
    pub heap_failure_calls: usize,
    pub drained_pcbs: usize,
    pub drained_memsets: usize,
    pub last_drain_pcbs: usize,
    pub last_drain_memsets: usize,
    pub last_backlog_pcbs: usize,
    pub last_backlog_memsets: usize,
}

lazy_static! {
    pub(super) static ref RECYCLED_PROCESSES: Mutex<Vec<ProcessControlBlock>> =
        Mutex::new(Vec::new());
    pub(super) static ref DEFERRED_ZOMBIE_MEMORY_RELEASES: Mutex<Vec<SharedMemorySet>> =
        Mutex::new(Vec::new());
}

#[inline]
pub(super) fn mark_recycle_work() {
    RECYCLE_WORK_FAST.store(1, Ordering::Relaxed);
}

pub(super) fn note_recycled_process_enqueued() {
    RECYCLE_ENQUEUED_PCBS.fetch_add(1, Ordering::Relaxed);
}

pub fn defer_zombie_memory_release(memory_set: SharedMemorySet) {
    mark_recycle_work();
    RECYCLE_ENQUEUED_MEMSETS.fetch_add(1, Ordering::Relaxed);
    DEFERRED_ZOMBIE_MEMORY_RELEASES.lock().push(memory_set);
}

fn recycle_backlog_counts() -> (usize, usize) {
    (
        RECYCLED_PROCESSES.lock().len(),
        DEFERRED_ZOMBIE_MEMORY_RELEASES.lock().len(),
    )
}

/// 只在回收队列有明显压力时做实际析构。
///
/// fork/exit/wait 微基准会在父进程 waitpid 热路径上反复回收短命子进程。
/// Linux 这类对象释放通常会通过延迟回收/RCU 分摊；这里保留语义上的
/// zombie reap，但避免每次 wait4 都同步释放整套地址空间元数据。
pub fn drain_recycled_processes_if_pressure() {
    let (queued_pcbs, queued_memsets) = recycle_backlog_counts();
    if queued_pcbs == 0 && queued_memsets == 0 {
        RECYCLE_WORK_FAST.store(0, Ordering::Relaxed);
        return;
    }
    let heap = crate::mm::kernel_heap_stats();
    let heap_pressure = heap.capacity > 0
        && heap.current.saturating_mul(RECYCLE_DRAIN_HEAP_PRESSURE_DEN)
            >= heap
                .capacity
                .saturating_mul(RECYCLE_DRAIN_HEAP_PRESSURE_NUM);
    if heap_pressure {
        RECYCLE_DRAIN_HEAP_PRESSURE_CALLS.fetch_add(1, Ordering::Relaxed);
        drain_recycled_processes_limited(
            recycle_drain_budget(
                queued_pcbs,
                RECYCLE_DRAIN_PCB_LOW_WATERMARK,
                RECYCLE_DRAIN_PCB_MAX_BATCH,
            ),
            RECYCLE_DRAIN_HEAP_MEMSET_BATCH_ITEMS,
        );
    } else if queued_memsets >= RECYCLE_DRAIN_MEMSET_HIGH_WATERMARK
        || queued_pcbs >= RECYCLE_DRAIN_PCB_HIGH_WATERMARK
    {
        RECYCLE_DRAIN_PRESSURE_CALLS.fetch_add(1, Ordering::Relaxed);
        drain_recycled_processes_limited(
            recycle_drain_budget(
                queued_pcbs,
                RECYCLE_DRAIN_PCB_LOW_WATERMARK,
                RECYCLE_DRAIN_PCB_MAX_BATCH,
            ),
            recycle_drain_budget(
                queued_memsets,
                RECYCLE_DRAIN_MEMSET_LOW_WATERMARK,
                RECYCLE_DRAIN_MEMSET_MAX_BATCH,
            ),
        );
    } else {
        // Small backlogs stay off the scheduler/wait hot path.  Once a high
        // watermark is reached, the shrinker above pulls the queues back to a
        // low watermark instead of letting long fork/exec runs pin old address
        // spaces indefinitely.
        RECYCLE_WORK_FAST.store(0, Ordering::Relaxed);
    }
}

fn recycle_drain_budget(queued: usize, low_watermark: usize, max_batch: usize) -> usize {
    queued.saturating_sub(low_watermark).min(max_batch)
}

/// 在不持有 PROCESS_MANAGER 锁的上下文中完成 PCB 和地址空间析构。
pub fn drain_recycled_processes() {
    drain_recycled_processes_limited(usize::MAX, usize::MAX);
}

pub fn drain_recycled_processes_for_heap_failure() {
    RECYCLE_DRAIN_HEAP_FAILURE_CALLS.fetch_add(1, Ordering::Relaxed);
