}

fn drain_recycled_processes_limited(mut pcb_budget: usize, mut memset_budget: usize) {
    RECYCLE_DRAIN_CALLS.fetch_add(1, Ordering::Relaxed);
    let (before_pcbs, before_memsets) = recycle_backlog_counts();
    RECYCLE_LAST_BACKLOG_PCBS.store(before_pcbs, Ordering::Relaxed);
    RECYCLE_LAST_BACKLOG_MEMSETS.store(before_memsets, Ordering::Relaxed);

    let mut drained_pcbs = 0usize;
    while pcb_budget > 0 {
        let pcb = {
            let mut recycled = RECYCLED_PROCESSES.lock();
            recycled.pop()
        };
        let Some(pcb) = pcb else {
            break;
        };
        pcb_budget -= 1;
        drained_pcbs += 1;

        if pcb.fd_table.is_unique_owner() {
            pcb.fd_table.with_mut(|fd_table| {
                crate::fs::vfs_core::api::vfs_api_cleanup_fd_table_on_exit(fd_table)
            });
        }
        drop(pcb);
    }

    let mut drained_memsets = 0usize;
    while memset_budget > 0 {
        let memory_set = {
            let mut deferred = DEFERRED_ZOMBIE_MEMORY_RELEASES.lock();
            deferred.pop()
        };
        let Some(memory_set) = memory_set else {
            break;
        };
        memset_budget -= 1;
        drained_memsets += 1;
        drop(memory_set);
    }

    RECYCLE_DRAINED_PCBS.fetch_add(drained_pcbs, Ordering::Relaxed);
    RECYCLE_DRAINED_MEMSETS.fetch_add(drained_memsets, Ordering::Relaxed);
    RECYCLE_LAST_DRAIN_PCBS.store(drained_pcbs, Ordering::Relaxed);
    RECYCLE_LAST_DRAIN_MEMSETS.store(drained_memsets, Ordering::Relaxed);

    let has_more =
        !RECYCLED_PROCESSES.lock().is_empty() || !DEFERRED_ZOMBIE_MEMORY_RELEASES.lock().is_empty();
    if !has_more {
        RECYCLE_WORK_FAST.store(0, Ordering::Relaxed);
    }
}

